using Microsoft.EntityFrameworkCore;
using ETFTracker.Api.Data;
using ETFTracker.Api.Dtos;
using ETFTracker.Api.Models;

namespace ETFTracker.Api.Services;

public interface IHoldingsService
{
    Task<DashboardDto> GetDashboardAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<HoldingDto>> GetHoldingsAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<TransactionDto>> GetHoldingHistoryAsync(int holdingId, CancellationToken cancellationToken = default);
    Task AddTransactionAsync(int userId, CreateTransactionDto dto, CancellationToken cancellationToken = default);
}

public class HoldingsService : IHoldingsService
{
    private readonly AppDbContext _context;
    private readonly IPriceService _priceService;
    private readonly ILogger<HoldingsService> _logger;

    public HoldingsService(AppDbContext context, IPriceService priceService, ILogger<HoldingsService> logger)
    {
        _context = context;
        _priceService = priceService;
        _logger = logger;
    }

    public async Task<DashboardDto> GetDashboardAsync(int userId, CancellationToken cancellationToken = default)
    {
        var holdings = await GetHoldingsAsync(userId, cancellationToken);

        var dashboard = new DashboardDto();

        // Calculate header metrics
        var totalValue = holdings.Sum(h => h.TotalValue);
        dashboard.Header.TotalHoldingsAmount = totalValue;

        dashboard.Header.DailyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.DailyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.DailyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.WeeklyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.WeeklyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.WeeklyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.MonthlyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.MonthlyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.MonthlyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.YtdMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.YtdMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.YtdMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Holdings = holdings;
        return dashboard;
    }

    public async Task<List<HoldingDto>> GetHoldingsAsync(int userId, CancellationToken cancellationToken = default)
    {
        var dbHoldings = await _context.Holdings
            .Where(h => h.UserId == userId)
            .Include(h => h.Transactions)
            .OrderBy(h => h.Ticker)
            .ToListAsync(cancellationToken);

        var holdingDtos = new List<HoldingDto>();

        foreach (var holding in dbHoldings)
        {
            var currentPrice = await _priceService.GetPriceAsync(holding.Ticker, cancellationToken);
            var totalValue = holding.Quantity * currentPrice;
            var totalInvested = holding.Quantity * holding.AverageCost;

            var holdingDto = new HoldingDto
            {
                Id = holding.Id,
                Ticker = holding.Ticker,
                EtfName = holding.EtfName,
                Quantity = holding.Quantity,
                AverageCost = holding.AverageCost,
                CurrentPrice = currentPrice,
                TotalValue = totalValue,
                DailyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 1, cancellationToken),
                WeeklyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 7, cancellationToken),
                MonthlyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 30, cancellationToken),
                YtdMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, DaysSinceYearStart(), cancellationToken)
            };

            holdingDtos.Add(holdingDto);
        }

        return holdingDtos;
    }

    public async Task<List<TransactionDto>> GetHoldingHistoryAsync(int holdingId, CancellationToken cancellationToken = default)
    {
        var transactions = await _context.Transactions
            .Where(t => t.HoldingId == holdingId)
            .OrderByDescending(t => t.PurchaseDate)
            .Select(t => new TransactionDto
            {
                Id = t.Id,
                HoldingId = t.HoldingId,
                Quantity = t.Quantity,
                PurchasePrice = t.PurchasePrice,
                PurchaseDate = t.PurchaseDate,
                CreatedAt = t.CreatedAt
            })
            .ToListAsync(cancellationToken);

        return transactions;
    }

    public async Task AddTransactionAsync(int userId, CreateTransactionDto dto, CancellationToken cancellationToken = default)
    {
        using var transaction = await _context.Database.BeginTransactionAsync(cancellationToken);

        try
        {
            // Get or create holding
            var holding = await _context.Holdings
                .FirstOrDefaultAsync(h => h.UserId == userId && h.Ticker == dto.Ticker, cancellationToken);

            if (holding == null)
            {
                holding = new Holding
                {
                    UserId = userId,
                    Ticker = dto.Ticker,
                    Quantity = 0,
                    AverageCost = 0
                };
                _context.Holdings.Add(holding);
                await _context.SaveChangesAsync(cancellationToken);
            }

            // Add transaction
            var newTransaction = new Transaction
            {
                HoldingId = holding.Id,
                Quantity = dto.Quantity,
                PurchasePrice = dto.PurchasePrice,
                PurchaseDate = dto.PurchaseDate
            };
            _context.Transactions.Add(newTransaction);
            await _context.SaveChangesAsync(cancellationToken);

            // Update holding average cost and quantity
            var allTransactions = await _context.Transactions
                .Where(t => t.HoldingId == holding.Id)
                .ToListAsync(cancellationToken);

            var totalQuantity = allTransactions.Sum(t => t.Quantity);
            var totalCost = allTransactions.Sum(t => t.Quantity * t.PurchasePrice);

            holding.Quantity = totalQuantity;
            holding.AverageCost = totalQuantity > 0 ? totalCost / totalQuantity : 0;
            holding.UpdatedAt = DateTime.UtcNow;

            _context.Holdings.Update(holding);
            await _context.SaveChangesAsync(cancellationToken);

            await transaction.CommitAsync(cancellationToken);
        }
        catch (Exception ex)
        {
            await transaction.RollbackAsync(cancellationToken);
            _logger.LogError(ex, "Error adding transaction");
            throw;
        }
    }

    private async Task<PeriodMetrics> CalculatePeriodMetricsAsync(string ticker, decimal totalInvested, int days, CancellationToken cancellationToken)
    {
        var currentPrice = await _priceService.GetPriceAsync(ticker, cancellationToken);
        var priceFromDaysAgo = await GetPriceFromDaysAgoAsync(ticker, days, cancellationToken);

        if (!priceFromDaysAgo.HasValue)
        {
            return new PeriodMetrics { GainLossEur = 0, GainLossPercent = 0 };
        }

        var totalValue = Decimal.MaxValue; // Quantity would be needed, using placeholder
        var gainLossEur = totalValue - totalInvested;
        var gainLossPercent = priceFromDaysAgo.Value > 0 
            ? ((currentPrice - priceFromDaysAgo.Value) / priceFromDaysAgo.Value) * 100 
            : 0;

        return new PeriodMetrics
        {
            GainLossEur = gainLossEur,
            GainLossPercent = gainLossPercent
        };
    }

    private async Task<decimal?> GetPriceFromDaysAgoAsync(string ticker, int days, CancellationToken cancellationToken)
    {
        var targetDate = DateTime.UtcNow.AddDays(-days).Date;

        // Try to get exact date first
        var snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate == targetDate)
            .OrderByDescending(ps => ps.CreatedAt)
            .FirstOrDefaultAsync(cancellationToken);

        if (snapshot != null)
            return snapshot.Price;

        // If not found, get the closest earlier snapshot
        snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate < targetDate)
            .OrderByDescending(ps => ps.SnapshotDate)
            .FirstOrDefaultAsync(cancellationToken);

        return snapshot?.Price;
    }

    private decimal CalculateWeightedPercentage(List<HoldingDto> holdings, Func<HoldingDto, decimal> percentSelector, Func<HoldingDto, decimal> weightSelector)
    {
        var totalWeight = holdings.Sum(weightSelector);
        if (totalWeight <= 0) return 0;

        return holdings.Sum(h => (percentSelector(h) / 100m) * weightSelector(h)) / totalWeight * 100;
    }

    private int DaysSinceYearStart()
    {
        var today = DateTime.UtcNow.Date;
        var yearStart = new DateTime(today.Year, 1, 1);
        return (today - yearStart).Days;
    }
}

using Microsoft.EntityFrameworkCore;
using ETFTracker.Api.Data;
using ETFTracker.Api.Dtos;
using ETFTracker.Api.Models;

namespace ETFTracker.Api.Services;

public interface IHoldingsService
{
    Task<DashboardDto> GetDashboardAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<HoldingDto>> GetHoldingsAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<TransactionDto>> GetHoldingHistoryAsync(int holdingId, CancellationToken cancellationToken = default);
    Task AddTransactionAsync(int userId, CreateTransactionDto dto, CancellationToken cancellationToken = default);
}

public class HoldingsService : IHoldingsService
{
    private readonly AppDbContext _context;
    private readonly IPriceService _priceService;
    private readonly ILogger<HoldingsService> _logger;

    public HoldingsService(AppDbContext context, IPriceService priceService, ILogger<HoldingsService> logger)
    {
        _context = context;
        _priceService = priceService;
        _logger = logger;
    }

    public async Task<DashboardDto> GetDashboardAsync(int userId, CancellationToken cancellationToken = default)
    {
        var holdings = await GetHoldingsAsync(userId, cancellationToken);

        var dashboard = new DashboardDto();

        // Calculate header metrics
        var totalValue = holdings.Sum(h => h.TotalValue);
        dashboard.Header.TotalHoldingsAmount = totalValue;

        dashboard.Header.DailyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.DailyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.DailyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.WeeklyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.WeeklyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.WeeklyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.MonthlyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.MonthlyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.MonthlyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.YtdMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.YtdMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.YtdMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Holdings = holdings;
        return dashboard;
    }

    public async Task<List<HoldingDto>> GetHoldingsAsync(int userId, CancellationToken cancellationToken = default)
    {
        var dbHoldings = await _context.Holdings
            .Where(h => h.UserId == userId)
            .Include(h => h.Transactions)
            .OrderBy(h => h.Ticker)
            .ToListAsync(cancellationToken);

        var holdingDtos = new List<HoldingDto>();

        foreach (var holding in dbHoldings)
        {
            var currentPrice = await _priceService.GetPriceAsync(holding.Ticker, cancellationToken);
            var totalValue = holding.Quantity * currentPrice;
            var totalInvested = holding.Quantity * holding.AverageCost;

            var holdingDto = new HoldingDto
            {
                Id = holding.Id,
                Ticker = holding.Ticker,
                EtfName = holding.EtfName,
                Quantity = holding.Quantity,
                AverageCost = holding.AverageCost,
                CurrentPrice = currentPrice,
                TotalValue = totalValue,
                DailyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 1, cancellationToken),
                WeeklyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 7, cancellationToken),
                MonthlyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 30, cancellationToken),
                YtdMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, DaysSinceYearStart(), cancellationToken)
            };

            holdingDtos.Add(holdingDto);
        }

        return holdingDtos;
    }

    public async Task<List<TransactionDto>> GetHoldingHistoryAsync(int holdingId, CancellationToken cancellationToken = default)
    {
        var transactions = await _context.Transactions
            .Where(t => t.HoldingId == holdingId)
            .OrderByDescending(t => t.PurchaseDate)
            .Select(t => new TransactionDto
            {
                Id = t.Id,
                HoldingId = t.HoldingId,
                Quantity = t.Quantity,
                PurchasePrice = t.PurchasePrice,
                PurchaseDate = t.PurchaseDate,
                CreatedAt = t.CreatedAt
            })
            .ToListAsync(cancellationToken);

        return transactions;
    }

    public async Task AddTransactionAsync(int userId, CreateTransactionDto dto, CancellationToken cancellationToken = default)
    {
        using var transaction = await _context.Database.BeginTransactionAsync(cancellationToken);

        try
        {
            // Get or create holding
            var holding = await _context.Holdings
                .FirstOrDefaultAsync(h => h.UserId == userId && h.Ticker == dto.Ticker, cancellationToken);

            if (holding == null)
            {
                holding = new Holding
                {
                    UserId = userId,
                    Ticker = dto.Ticker,
                    Quantity = 0,
                    AverageCost = 0
                };
                _context.Holdings.Add(holding);
                await _context.SaveChangesAsync(cancellationToken);
            }

            // Add transaction
            var newTransaction = new Transaction
            {
                HoldingId = holding.Id,
                Quantity = dto.Quantity,
                PurchasePrice = dto.PurchasePrice,
                PurchaseDate = dto.PurchaseDate
            };
            _context.Transactions.Add(newTransaction);
            await _context.SaveChangesAsync(cancellationToken);

            // Update holding average cost and quantity
            var allTransactions = await _context.Transactions
                .Where(t => t.HoldingId == holding.Id)
                .ToListAsync(cancellationToken);

            var totalQuantity = allTransactions.Sum(t => t.Quantity);
            var totalCost = allTransactions.Sum(t => t.Quantity * t.PurchasePrice);

            holding.Quantity = totalQuantity;
            holding.AverageCost = totalQuantity > 0 ? totalCost / totalQuantity : 0;
            holding.UpdatedAt = DateTime.UtcNow;

            _context.Holdings.Update(holding);
            await _context.SaveChangesAsync(cancellationToken);

            await transaction.CommitAsync(cancellationToken);
        }
        catch (Exception ex)
        {
            await transaction.RollbackAsync(cancellationToken);
            _logger.LogError(ex, "Error adding transaction");
            throw;
        }
    }

    private async Task<PeriodMetrics> CalculatePeriodMetricsAsync(string ticker, decimal quantity, int days, CancellationToken cancellationToken)
    {
        var currentPrice = await _priceService.GetPriceAsync(ticker, cancellationToken);
        var priceFromDaysAgo = await GetPriceFromDaysAgoAsync(ticker, days, cancellationToken);

        if (!priceFromDaysAgo.HasValue)
        {
            return new PeriodMetrics { GainLossEur = 0, GainLossPercent = 0 };
        }

        var gainLossEur = (currentPrice - priceFromDaysAgo.Value) * quantity;
        var gainLossPercent = priceFromDaysAgo.Value > 0 
            ? ((currentPrice - priceFromDaysAgo.Value) / priceFromDaysAgo.Value) * 100 
            : 0;

        return new PeriodMetrics
        {
            GainLossEur = gainLossEur,
            GainLossPercent = gainLossPercent
        };
    }

    private async Task<decimal?> GetPriceFromDaysAgoAsync(string ticker, int days, CancellationToken cancellationToken)
    {
        var targetDate = DateTime.UtcNow.AddDays(-days).Date;

        // Try to get exact date first
        var snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate == targetDate)
            .OrderByDescending(ps => ps.CreatedAt)
            .FirstOrDefaultAsync(cancellationToken);

        if (snapshot != null)
            return snapshot.Price;

        // If not found, get the closest earlier snapshot
        snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate < targetDate)
            .OrderByDescending(ps => ps.SnapshotDate)
            .FirstOrDefaultAsync(cancellationToken);

        return snapshot?.Price;
    }

    private decimal CalculateWeightedPercentage(List<HoldingDto> holdings, Func<HoldingDto, decimal> percentSelector, Func<HoldingDto, decimal> weightSelector)
    {
        var totalWeight = holdings.Sum(weightSelector);
        if (totalWeight <= 0) return 0;

        return holdings.Sum(h => (percentSelector(h) / 100m) * weightSelector(h)) / totalWeight * 100;
    }

    private int DaysSinceYearStart()
    {
        var today = DateTime.UtcNow.Date;
        var yearStart = new DateTime(today.Year, 1, 1);
        return (today - yearStart).Days;
    }
}

using Microsoft.AspNetCore.Authentication;
using Microsoft.AspNetCore.Authentication.Cookies;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System.Security.Claims;
using ETFTracker.Api.Data;
using ETFTracker.Api.Models;
using ETFTracker.Api.Services;

namespace ETFTracker.Api.Controllers;

[ApiController]
[Route("api/auth")]
public class AuthController : ControllerBase
{
    private readonly AppDbContext    _db;
    private readonly JwtService      _jwtService;
    private readonly IConfiguration  _configuration;
    private readonly ILogger<AuthController> _logger;

    public AuthController(
        AppDbContext db,
        JwtService jwtService,
        IConfiguration configuration,
        ILogger<AuthController> logger)
    {
        _db            = db;
        _jwtService    = jwtService;
        _configuration = configuration;
        _logger        = logger;
    }

    // ── GitHub ─────────────────────────────────────────────────────────────────

    [HttpGet("github")]
    public IActionResult LoginWithGitHub()
    {
        var redirectUri = Url.Action(nameof(GitHubComplete), "Auth", null, Request.Scheme)!;
        return Challenge(new AuthenticationProperties { RedirectUri = redirectUri }, "GitHub");
    }

    [HttpGet("github/complete")]
    public async Task<IActionResult> GitHubComplete(CancellationToken ct = default)
        => await HandleOAuthComplete("GitHub", ct);

    // ── Google ─────────────────────────────────────────────────────────────────

    [HttpGet("google")]
    public IActionResult LoginWithGoogle()
    {
        var redirectUri = Url.Action(nameof(GoogleComplete), "Auth", null, Request.Scheme)!;
        return Challenge(new AuthenticationProperties { RedirectUri = redirectUri }, "Google");
    }

    [HttpGet("google/complete")]
    public async Task<IActionResult> GoogleComplete(CancellationToken ct = default)
        => await HandleOAuthComplete("Google", ct);

    // ── Me ─────────────────────────────────────────────────────────────────────

    [Authorize]
    [HttpGet("me")]
    public IActionResult GetCurrentUser() => Ok(new
    {
        userId        = User.FindFirst("userId")?.Value,
        email         = User.FindFirst("email")?.Value,
        name          = User.FindFirst("name")?.Value,
        avatarUrl     = User.FindFirst("avatarUrl")?.Value,
        githubUsername = User.FindFirst("githubUsername")?.Value,
    });

    // ── Shared handler ─────────────────────────────────────────────────────────

    private async Task<IActionResult> HandleOAuthComplete(string provider, CancellationToken ct)
    {
        var frontendUrl = _configuration["Frontend:BaseUrl"] ?? "http://localhost:4200";

        // Read the user that the OAuth middleware signed in to the external cookie
        var result = await HttpContext.AuthenticateAsync(CookieAuthenticationDefaults.AuthenticationScheme);
        if (!result.Succeeded)
        {
            _logger.LogWarning("OAuth sign-in failed for {Provider}: {Error}", provider, result.Failure?.Message);
            return Redirect($"{frontendUrl}/login?error=oauth_failed");
        }

        var principal = result.Principal!;
        var now       = DateTime.UtcNow;
        User? user;

        if (provider == "GitHub")
        {
            var githubId       = principal.FindFirst(ClaimTypes.NameIdentifier)?.Value;
            var githubUsername = principal.FindFirst("urn:github:login")?.Value;
            var email          = principal.FindFirst(ClaimTypes.Email)?.Value;
            var name           = principal.FindFirst(ClaimTypes.Name)?.Value
                              ?? principal.FindFirst("urn:github:name")?.Value;
            var avatarUrl      = principal.FindFirst("urn:github:avatar")?.Value;

            _logger.LogInformation("GitHub OAuth – id:{Id} login:{Login} email:{Email}", githubId, githubUsername, email);

            // 1. By GitHub ID
            user = await _db.Users.FirstOrDefaultAsync(u => u.GitHubId == githubId, ct);
            // 2. By pre-seeded GitHub username (links DenisBahia's existing data)
            user ??= await _db.Users.FirstOrDefaultAsync(u => u.GitHubUsername == githubUsername, ct);
            // 3. By email
            if (user == null && !string.IsNullOrEmpty(email))
                user = await _db.Users.FirstOrDefaultAsync(u => u.Email == email, ct);

            if (user == null)
            {
                var parts = (name ?? "").Split(' ', 2);
                user = new User
                {
                    Email          = email,
                    FirstName      = parts.Length > 0 ? parts[0] : null,
                    LastName       = parts.Length > 1 ? parts[1] : null,
                    AvatarUrl      = avatarUrl,
                    GitHubId       = githubId,
                    GitHubUsername = githubUsername,
                    CreatedAt      = now,
                    UpdatedAt      = now
                };
                _db.Users.Add(user);
            }
            else
            {
                user.GitHubId       = githubId;
                user.GitHubUsername ??= githubUsername;
                user.AvatarUrl      ??= avatarUrl;
                user.Email          ??= email;
                user.UpdatedAt       = now;
            }
        }
        else // Google
        {
            var googleId  = principal.FindFirst(ClaimTypes.NameIdentifier)?.Value;
            var email     = principal.FindFirst(ClaimTypes.Email)?.Value;
            var firstName = principal.FindFirst(ClaimTypes.GivenName)?.Value;
            var lastName  = principal.FindFirst(ClaimTypes.Surname)?.Value;
            var avatarUrl = principal.FindFirst("urn:google:picture")?.Value
                         ?? principal.FindFirst("picture")?.Value;

            _logger.LogInformation("Google OAuth – id:{Id} email:{Email}", googleId, email);

            // 1. By Google ID
            user = await _db.Users.FirstOrDefaultAsync(u => u.GoogleId == googleId, ct);
            // 2. By email
            if (user == null && !string.IsNullOrEmpty(email))
                user = await _db.Users.FirstOrDefaultAsync(u => u.Email == email, ct);

            if (user == null)
            {
                user = new User
                {
                    Email     = email,
                    FirstName = firstName,
                    LastName  = lastName,
                    AvatarUrl = avatarUrl,
                    GoogleId  = googleId,
                    CreatedAt = now,
                    UpdatedAt = now
                };
                _db.Users.Add(user);
            }
            else
            {
                user.GoogleId  = googleId;
                user.AvatarUrl ??= avatarUrl;
                user.Email     ??= email;
                user.UpdatedAt  = now;
            }
        }

        await _db.SaveChangesAsync(ct);

        // Sign out the temporary external cookie now that we have our own JWT
        await HttpContext.SignOutAsync(CookieAuthenticationDefaults.AuthenticationScheme);

        var token = _jwtService.GenerateToken(user);
        return Redirect($"{frontendUrl}/auth/callback?token={Uri.EscapeDataString(token)}");
    }
}

using Microsoft.AspNetCore.Mvc;
using ETFTracker.Api.Dtos;
using ETFTracker.Api.Services;

namespace ETFTracker.Api.Controllers;

[ApiController]
[Route("api/[controller]")]
public class HoldingsController : ControllerBase
{
    private readonly IHoldingsService _holdingsService;
    private readonly IPriceService _priceService;
    private readonly ILogger<HoldingsController> _logger;
    private const int DefaultUserId = 1; // Temporary: will use authenticated user later

    public HoldingsController(IHoldingsService holdingsService, IPriceService priceService, ILogger<HoldingsController> logger)
    {
        _holdingsService = holdingsService;
        _priceService = priceService;
        _logger = logger;
    }

    [HttpGet("etf-description/{ticker}")]
    public async Task<ActionResult<object>> GetEtfDescription(string ticker, CancellationToken cancellationToken = default)
    {
        try
        {
            if (string.IsNullOrWhiteSpace(ticker))
                return BadRequest(new { message = "Ticker is required" });

            var description = await _priceService.GetEtfDescriptionAsync(ticker.ToUpper(), cancellationToken);
            return Ok(new { description = description ?? "ETF not found" });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error getting ETF description for {ticker}");
            return StatusCode(500, new { message = "Error retrieving ETF description" });
        }
    }

    [HttpGet("portfolio-evolution")]
    public async Task<ActionResult<PortfolioEvolutionDto>> GetPortfolioEvolution(CancellationToken cancellationToken = default)
    {
        try
        {
            var evolution = await _holdingsService.GetPortfolioEvolutionAsync(DefaultUserId, cancellationToken);
            return Ok(evolution);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error getting portfolio evolution");
            return StatusCode(500, new { message = "Error retrieving portfolio evolution" });
        }
    }

    [HttpGet("dashboard")]
    public async Task<ActionResult<DashboardDto>> GetDashboard(CancellationToken cancellationToken = default)
    {
        try
        {
            _logger.LogInformation("Getting dashboard for user {UserId}", DefaultUserId);
            var dashboard = await _holdingsService.GetDashboardAsync(DefaultUserId, cancellationToken);
            _logger.LogInformation("Dashboard retrieved successfully");
            return Ok(dashboard);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error getting dashboard");
            return StatusCode(500, new { message = "Error retrieving dashboard" });
        }
    }

    [HttpGet]
    public async Task<ActionResult<List<HoldingDto>>> GetHoldings(CancellationToken cancellationToken = default)
    {
        try
        {
            var holdings = await _holdingsService.GetHoldingsAsync(DefaultUserId, cancellationToken);
            return Ok(holdings);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error getting holdings");
            return StatusCode(500, new { message = "Error retrieving holdings" });
        }
    }

    [HttpGet("{holdingId}/history")]
    public async Task<ActionResult<List<TransactionDto>>> GetHoldingHistory(int holdingId, CancellationToken cancellationToken = default)
    {
        try
        {
            var history = await _holdingsService.GetHoldingHistoryAsync(holdingId, cancellationToken);
            return Ok(history);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error getting history for holding {holdingId}");
            return StatusCode(500, new { message = "Error retrieving holding history" });
        }
    }

    [HttpPost("transaction")]
    public async Task<ActionResult> AddTransaction([FromBody] CreateTransactionDto dto, CancellationToken cancellationToken = default)
    {
        try
        {
            if (!ModelState.IsValid)
                return BadRequest(ModelState);

            await _holdingsService.AddTransactionAsync(DefaultUserId, dto, cancellationToken);
            return Ok(new { message = "Transaction added successfully" });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error adding transaction");
            return StatusCode(500, new { message = "Error adding transaction" });
        }
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Authorization;
using ETFTracker.Api.Dtos;
using ETFTracker.Api.Services;

namespace ETFTracker.Api.Controllers;

[Authorize]
[ApiController]
[Route("api/[controller]")]
public class HoldingsController : ControllerBase
{
    private readonly IHoldingsService _holdingsService;
    private readonly IPriceService _priceService;
    private readonly ILogger<HoldingsController> _logger;

    public HoldingsController(IHoldingsService holdingsService, IPriceService priceService, ILogger<HoldingsController> logger)
    {
        _holdingsService = holdingsService;
        _priceService = priceService;
        _logger = logger;
    }

    private int GetUserId() =>
        int.Parse(User.FindFirst("userId")?.Value
            ?? throw new UnauthorizedAccessException("userId claim missing"));

    [HttpGet("etf-description/{ticker}")]
    public async Task<ActionResult<object>> GetEtfDescription(string ticker, CancellationToken cancellationToken = default)
    {
        try
        {
            if (string.IsNullOrWhiteSpace(ticker))
                return BadRequest(new { message = "Ticker is required" });

            var description = await _priceService.GetEtfDescriptionAsync(ticker.ToUpper(), cancellationToken);
            return Ok(new { description = description ?? "ETF not found" });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error getting ETF description for {ticker}");
            return StatusCode(500, new { message = "Error retrieving ETF description" });
        }
    }

    [HttpGet("portfolio-evolution")]
    public async Task<ActionResult<PortfolioEvolutionDto>> GetPortfolioEvolution(CancellationToken cancellationToken = default)
    {
        try
        {
            var evolution = await _holdingsService.GetPortfolioEvolutionAsync(GetUserId(), cancellationToken);
            return Ok(evolution);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error getting portfolio evolution");
            return StatusCode(500, new { message = "Error retrieving portfolio evolution" });
        }
    }

    [HttpGet("dashboard")]
    public async Task<ActionResult<DashboardDto>> GetDashboard(CancellationToken cancellationToken = default)
    {
        try
        {
            _logger.LogInformation("Getting dashboard for user {UserId}", GetUserId());
            var dashboard = await _holdingsService.GetDashboardAsync(GetUserId(), cancellationToken);
            _logger.LogInformation("Dashboard retrieved successfully");
            return Ok(dashboard);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error getting dashboard");
            return StatusCode(500, new { message = "Error retrieving dashboard" });
        }
    }

    [HttpGet]
    public async Task<ActionResult<List<HoldingDto>>> GetHoldings(CancellationToken cancellationToken = default)
    {
        try
        {
            var holdings = await _holdingsService.GetHoldingsAsync(GetUserId(), cancellationToken);
            return Ok(holdings);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error getting holdings");
            return StatusCode(500, new { message = "Error retrieving holdings" });
        }
    }

    [HttpGet("{holdingId}/history")]
    public async Task<ActionResult<List<TransactionDto>>> GetHoldingHistory(int holdingId, CancellationToken cancellationToken = default)
    {
        try
        {
            var history = await _holdingsService.GetHoldingHistoryAsync(holdingId, cancellationToken);
            return Ok(history);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error getting history for holding {holdingId}");
            return StatusCode(500, new { message = "Error retrieving holding history" });
        }
    }

    [HttpPost("transaction")]
    public async Task<ActionResult> AddTransaction([FromBody] CreateTransactionDto dto, CancellationToken cancellationToken = default)
    {
        try
        {
            if (!ModelState.IsValid)
                return BadRequest(ModelState);

            await _holdingsService.AddTransactionAsync(GetUserId(), dto, cancellationToken);
            return Ok(new { message = "Transaction added successfully" });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error adding transaction");
            return StatusCode(500, new { message = "Error adding transaction" });
        }
    }
}

using Microsoft.AspNetCore.Mvc;
using ETFTracker.Api.Dtos;
using ETFTracker.Api.Services;

namespace ETFTracker.Api.Controllers;

[ApiController]
[Route("api/[controller]")]
public class ProjectionsController : ControllerBase
{
    private readonly IProjectionService _projectionService;
    private readonly ILogger<ProjectionsController> _logger;
    private const int DefaultUserId = 1;

    public ProjectionsController(IProjectionService projectionService, ILogger<ProjectionsController> logger)
    {
        _projectionService = projectionService;
        _logger = logger;
    }

    /// <summary>
    /// Returns current projection settings + calculated data points.
    /// </summary>
    [HttpGet]
    public async Task<ActionResult<ProjectionResultDto>> GetProjection(CancellationToken ct = default)
    {
        try
        {
            var result = await _projectionService.GetProjectionAsync(DefaultUserId, ct);
            return Ok(result);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error calculating projection");
            return StatusCode(500, new { message = "Error calculating projection" });
        }
    }

    /// <summary>
    /// Saves projection settings and returns the saved values.
    /// </summary>
    [HttpPut("settings")]
    public async Task<ActionResult<ProjectionSettingsDto>> SaveSettings(
        [FromBody] ProjectionSettingsDto dto,
        CancellationToken ct = default)
    {
        try
        {
            if (!ModelState.IsValid)
                return BadRequest(ModelState);

            var saved = await _projectionService.SaveSettingsAsync(DefaultUserId, dto, ct);
            return Ok(saved);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error saving projection settings");
            return StatusCode(500, new { message = "Error saving projection settings" });
        }
    }
}

