using Microsoft.EntityFrameworkCore;
using ETFTracker.Api.Data;
using ETFTracker.Api.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container
builder.Services.AddControllers();
builder.Services.AddOpenApi();

// Add DbContext
var connectionString = builder.Configuration.GetConnectionString("DefaultConnection");
builder.Services.AddDbContext<AppDbContext>(options =>
    options.UseNpgsql(connectionString, b => b.MigrationsAssembly("ETFTracker.Api")));

// Register services
builder.Services.AddScoped<IPriceService, PriceService>();
builder.Services.AddScoped<IHoldingsService, HoldingsService>();
builder.Services.AddScoped<IProjectionService, ProjectionService>();
builder.Services.AddHttpClient<PriceService>();

// Add CORS
builder.Services.AddCors(options =>
{
    options.AddPolicy("AllowAngular", policy =>
    {
        policy.AllowAnyOrigin()
              .AllowAnyMethod()
              .AllowAnyHeader();
    });
});

var app = builder.Build();

// Configure the HTTP request pipeline
if (app.Environment.IsDevelopment())
{
    app.MapOpenApi();
}

app.UseCors("AllowAngular");

// Serve static files (Angular app)
app.UseDefaultFiles();
app.UseStaticFiles();

app.MapControllers();

// Fallback to index.html for SPA routing
app.MapFallbackToFile("index.html");

// Ensure database is created and seeded
using (var scope = app.Services.CreateScope())
{
    var db = scope.ServiceProvider.GetRequiredService<AppDbContext>();
    // Use Migrate() instead of EnsureCreated() to apply EF Core migrations
    db.Database.Migrate();

    // Seed default user if it doesn't exist
    if (!db.Users.Any())
    {
        var utcNow = new DateTime(DateTime.UtcNow.Ticks, DateTimeKind.Utc);
        var defaultUser = new ETFTracker.Api.Models.User
        {
            Email = "demo@example.com",
            FirstName = "Demo",
            LastName = "User",
            CreatedAt = utcNow,
            UpdatedAt = utcNow
        };
        db.Users.Add(defaultUser);
        db.SaveChanges();
    }
}

app.Run();

using System.Text;
using System.Security.Claims;
using Microsoft.AspNetCore.Authentication.Cookies;
using Microsoft.AspNetCore.Authentication.JwtBearer;
using Microsoft.EntityFrameworkCore;
using Microsoft.IdentityModel.Tokens;
using ETFTracker.Api.Data;
using ETFTracker.Api.Services;

var builder = WebApplication.CreateBuilder(args);

// ── Core ──────────────────────────────────────────────────────────────────────
builder.Services.AddControllers();
builder.Services.AddOpenApi();

// ── Database ──────────────────────────────────────────────────────────────────
var connectionString = builder.Configuration.GetConnectionString("DefaultConnection");
builder.Services.AddDbContext<AppDbContext>(options =>
    options.UseNpgsql(connectionString, b => b.MigrationsAssembly("ETFTracker.Api")));

// ── App services ──────────────────────────────────────────────────────────────
builder.Services.AddScoped<IPriceService, PriceService>();
builder.Services.AddScoped<IHoldingsService, HoldingsService>();
builder.Services.AddScoped<IProjectionService, ProjectionService>();
builder.Services.AddScoped<JwtService>();
builder.Services.AddHttpClient<PriceService>();

// ── Authentication ────────────────────────────────────────────────────────────
var jwtKey = builder.Configuration["Jwt:Key"]
    ?? throw new InvalidOperationException("Jwt:Key is not configured. Use dotnet user-secrets or environment variables.");

builder.Services.AddAuthentication(options =>
{
    // JWT is the default for API endpoints
    options.DefaultAuthenticateScheme = JwtBearerDefaults.AuthenticationScheme;
    options.DefaultChallengeScheme    = JwtBearerDefaults.AuthenticationScheme;
    // Cookies are used as a temporary store during the OAuth callback flow
    options.DefaultSignInScheme       = CookieAuthenticationDefaults.AuthenticationScheme;
})
.AddCookie(CookieAuthenticationDefaults.AuthenticationScheme, o =>
{
    o.ExpireTimeSpan = TimeSpan.FromMinutes(10); // short-lived – only for OAuth handshake
})
.AddJwtBearer(options =>
{
    options.TokenValidationParameters = new TokenValidationParameters
    {
        ValidateIssuer           = true,
        ValidateAudience         = true,
        ValidateLifetime         = true,
        ValidateIssuerSigningKey = true,
        ValidIssuer              = builder.Configuration["Jwt:Issuer"]   ?? "ETFTracker",
        ValidAudience            = builder.Configuration["Jwt:Audience"] ?? "ETFTracker",
        IssuerSigningKey         = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(jwtKey))
    };
})
.AddGitHub(options =>
{
    options.ClientId     = builder.Configuration["OAuth:GitHub:ClientId"]
        ?? throw new InvalidOperationException("OAuth:GitHub:ClientId not configured.");
    options.ClientSecret = builder.Configuration["OAuth:GitHub:ClientSecret"]
        ?? throw new InvalidOperationException("OAuth:GitHub:ClientSecret not configured.");
    // /signin-github is handled automatically by the middleware
    options.Scope.Add("user:email");
    options.Events.OnCreatingTicket = ctx =>
    {
        // Map extra GitHub fields (login, name, avatar_url) as custom claims
        if (ctx.User.TryGetProperty("login", out var login))
            ctx.Identity?.AddClaim(new Claim("urn:github:login", login.GetString() ?? ""));
        if (ctx.User.TryGetProperty("name", out var name))
            ctx.Identity?.AddClaim(new Claim("urn:github:name", name.GetString() ?? ""));
        if (ctx.User.TryGetProperty("avatar_url", out var avatar))
            ctx.Identity?.AddClaim(new Claim("urn:github:avatar", avatar.GetString() ?? ""));
        return Task.CompletedTask;
    };
})
.AddGoogle(options =>
{
    options.ClientId     = builder.Configuration["OAuth:Google:ClientId"]
        ?? throw new InvalidOperationException("OAuth:Google:ClientId not configured.");
    options.ClientSecret = builder.Configuration["OAuth:Google:ClientSecret"]
        ?? throw new InvalidOperationException("OAuth:Google:ClientSecret not configured.");
    options.Events.OnCreatingTicket = ctx =>
    {
        if (ctx.User.TryGetProperty("picture", out var pic))
            ctx.Identity?.AddClaim(new Claim("picture", pic.GetString() ?? ""));
        return Task.CompletedTask;
    };
    options.SaveTokens = true;
});

builder.Services.AddAuthorization();

// ── CORS ──────────────────────────────────────────────────────────────────────
var frontendUrl = builder.Configuration["Frontend:BaseUrl"] ?? "http://localhost:4200";
builder.Services.AddCors(options =>
{
    options.AddPolicy("AllowAngular", policy =>
    {
        policy.WithOrigins(frontendUrl)
              .AllowAnyMethod()
              .AllowAnyHeader()
              .AllowCredentials();
    });
});

var app = builder.Build();

// ── Pipeline ──────────────────────────────────────────────────────────────────
if (app.Environment.IsDevelopment())
    app.MapOpenApi();

app.UseCors("AllowAngular");
app.UseAuthentication();
app.UseAuthorization();

app.UseDefaultFiles();
app.UseStaticFiles();

app.MapControllers();
app.MapFallbackToFile("index.html");

// ── Startup ───────────────────────────────────────────────────────────────────
using (var scope = app.Services.CreateScope())
{
    var db = scope.ServiceProvider.GetRequiredService<AppDbContext>();
    db.Database.Migrate();

    // Pre-tag the existing user (id=1) with the GitHub username so the first
    // login from GitHub as DenisBahia automatically merges with existing data.
    var existingUser = db.Users.FirstOrDefault(u => u.Id == 1);
    if (existingUser != null && existingUser.GitHubUsername == null)
    {
        existingUser.GitHubUsername = "DenisBahia";
        db.SaveChanges();
    }
}

app.Run();

using System.IdentityModel.Tokens.Jwt;
using System.Security.Claims;
using System.Text;
using Microsoft.IdentityModel.Tokens;
using ETFTracker.Api.Models;

namespace ETFTracker.Api.Services;

public class JwtService
{
    private readonly IConfiguration _configuration;

    public JwtService(IConfiguration configuration)
    {
        _configuration = configuration;
    }

    public string GenerateToken(User user)
    {
        var jwtKey = _configuration["Jwt:Key"]
            ?? throw new InvalidOperationException("JWT Key is not configured.");
        var issuer    = _configuration["Jwt:Issuer"]   ?? "ETFTracker";
        var audience  = _configuration["Jwt:Audience"] ?? "ETFTracker";
        var expiryDays = int.Parse(_configuration["Jwt:ExpiryDays"] ?? "30");

        var key         = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(jwtKey));
        var credentials = new SigningCredentials(key, SecurityAlgorithms.HmacSha256);

        var claims = new List<Claim>
        {
            new(JwtRegisteredClaimNames.Sub, user.Id.ToString()),
            new(JwtRegisteredClaimNames.Jti, Guid.NewGuid().ToString()),
            new("userId",          user.Id.ToString()),
            new("email",           user.Email           ?? ""),
            new("name",            $"{user.FirstName} {user.LastName}".Trim()),
            new("avatarUrl",       user.AvatarUrl       ?? ""),
            new("githubUsername",  user.GitHubUsername  ?? ""),
        };

        var token = new JwtSecurityToken(
            issuer:            issuer,
            audience:          audience,
            claims:            claims,
            expires:           DateTime.UtcNow.AddDays(expiryDays),
            signingCredentials: credentials
        );

        return new JwtSecurityTokenHandler().WriteToken(token);
    }
}

