import { inject } from '@angular/core';
import { CanActivateFn, Router } from '@angular/router';
import { AuthService } from '../services/auth.service';

export const authGuard: CanActivateFn = () => {
  const auth   = inject(AuthService);
  const router = inject(Router);

  if (auth.isAuthenticated()) return true;

  router.navigate(['/login']);
  return false;
};

import { HttpInterceptorFn } from '@angular/common/http';
import { inject } from '@angular/core';
import { AuthService } from '../services/auth.service';

export const authInterceptor: HttpInterceptorFn = (req, next) => {
  const token = inject(AuthService).getToken();
  if (token) {
    return next(req.clone({ setHeaders: { Authorization: `Bearer ${token}` } }));
  }
  return next(req);
};

import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-auth-callback',
  standalone: true,
  template: `
    <div style="min-height:100vh;display:flex;align-items:center;justify-content:center;
                background:var(--bg-surface);color:var(--text-muted);font-size:1rem;">
      Signing you in…
    </div>
  `
})
export class AuthCallbackComponent implements OnInit {
  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private auth: AuthService
  ) {}

  ngOnInit(): void {
    const token = this.route.snapshot.queryParamMap.get('token');
    if (token) {
      this.auth.handleToken(token);
      this.router.navigate(['/dashboard'], { replaceUrl: true });
    } else {
      this.router.navigate(['/login'], { replaceUrl: true });
    }
  }
}

// ── Shared helpers ──────────────────────────────────────────────────────────
%card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--shadow-md);
}

%section-heading {
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: 0.04em;
  text-transform: uppercase;
  margin-bottom: 1.25rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;

  &::before {
    content: '';
    display: inline-block;
    width: 3px;
    height: 1em;
    border-radius: 2px;
    background: var(--accent);
  }
}

// ── Dashboard shell ─────────────────────────────────────────────────────────
.dashboard-container {
  padding: 2rem 2.5rem;
  max-width: 1700px;
  margin: 0 auto;

  // Loading & error states
  .loading, .error {
    text-align: center;
    padding: 4rem 2rem;
    font-size: 1rem;
    color: var(--text-secondary);

    button {
      margin-top: 1.25rem;
      padding: 0.6rem 1.75rem;
      background: var(--accent);
      color: #fff;
      border: none;
      border-radius: 8px;
      cursor: pointer;
      font-weight: 600;
      transition: background 0.2s;

      &:hover { background: var(--accent-hover); }
    }
  }

  .error {
    @extend %card;
    color: var(--negative);
    border-color: rgba(240, 82, 82, 0.3);
    background: rgba(240, 82, 82, 0.06);
  }

  // ── Dashboard content ──────────────────────────────────────────────────────
  .dashboard-content {

    // ── HEADER ────────────────────────────────────────────────────────────────
    .dashboard-header {
      margin-bottom: 2.5rem;

      h1 {
        font-size: 1.65rem;
        font-weight: 800;
        letter-spacing: -0.03em;
        color: var(--text-primary);
        margin-bottom: 1.75rem;
        display: flex;
        align-items: center;
        gap: 0.75rem;

        &::after {
          content: '';
          flex: 1;
          height: 1px;
          background: var(--border);
        }
      }

      // Metric cards grid
      .metrics-grid {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
        gap: 1rem;
        margin-bottom: 1.5rem;

        .metric-card {
          @extend %card;
          padding: 1.35rem 1.5rem;
          position: relative;
          overflow: hidden;
          transition: transform 0.18s, box-shadow 0.18s;

          &::before {
            content: '';
            position: absolute;
            top: 0; left: 0; right: 0;
            height: 2px;
            background: var(--border-light);
            transition: background 0.2s;
          }

          &:hover {
            transform: translateY(-3px);
            box-shadow: 0 8px 28px rgba(0,0,0,0.55);
            &::before { background: var(--accent); }
          }

          .metric-label {
            font-size: 0.72rem;
            font-weight: 600;
            color: var(--text-muted);
            text-transform: uppercase;
            letter-spacing: 0.08em;
            margin-bottom: 0.65rem;
            display: flex;
            align-items: center;
            gap: 0.4rem;

            .exclamation-mark {
              display: inline-flex;
              align-items: center;
              justify-content: center;
              width: 1.15rem;
              height: 1.15rem;
              background: var(--negative);
              color: #fff;
              border-radius: 50%;
              font-size: 0.7rem;
              font-weight: 700;
              flex-shrink: 0;
            }
          }

          .metric-value {
            font-size: 1.65rem;
            font-weight: 800;
            letter-spacing: -0.03em;
            color: var(--text-primary);
            margin-bottom: 0.25rem;
            font-variant-numeric: tabular-nums;
          }

          .metric-percent {
            font-size: 0.9rem;
            font-weight: 600;
            color: var(--text-secondary);
          }

          .price-unavailable-message {
            font-size: 0.75rem;
            color: var(--negative);
            margin-top: 0.6rem;
            font-style: italic;
            background: var(--negative-bg);
            padding: 0.35rem 0.6rem;
            border-radius: 5px;
          }

          // Total Holdings – blue gradient hero card
          &.total {
            background: linear-gradient(135deg, #1a3a6e 0%, #0f224d 100%);
            border-color: rgba(79, 142, 247, 0.3);

            &::before { background: var(--accent); }

            .metric-label { color: rgba(228, 234, 245, 0.6); }
            .metric-value { color: #fff; font-size: 1.9rem; }
          }

          &.positive {
            .metric-value, .metric-percent { color: var(--positive); }
            &::before { background: var(--positive); }
          }

          &.negative {
            .metric-value, .metric-percent { color: var(--negative); }
            &::before { background: var(--negative); }
          }
        }
      }

      .action-buttons {
        display: flex;
        gap: 0.75rem;

        .btn {
          padding: 0.65rem 1.5rem;
          font-size: 0.9rem;
          border: none;
          border-radius: 8px;
          cursor: pointer;
          font-weight: 600;
          transition: all 0.18s;
          letter-spacing: 0.02em;

          &.btn-primary {
            background: var(--accent);
            color: #fff;
            box-shadow: 0 0 0 0 var(--accent-glow);

            &:hover {
              background: var(--accent-hover);
              box-shadow: 0 0 0 4px var(--accent-glow);
            }
          }
        }
      }
    }

    // ── PROJECTION SECTION ─────────────────────────────────────────────────
    .projection-section {
      @extend %card;
      padding: 1.75rem;
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      // Parameter inputs row
      .projection-params {
        display: flex;
        flex-wrap: wrap;
        align-items: flex-end;
        gap: 1rem;
        margin-bottom: 1.75rem;
        padding: 1.25rem;
        background: var(--bg-surface);
        border: 1px solid var(--border);
        border-radius: 8px;

        .param-group {
          display: flex;
          flex-direction: column;
          gap: 0.35rem;

          label {
            font-size: 0.68rem;
            font-weight: 600;
            color: var(--text-muted);
            text-transform: uppercase;
            letter-spacing: 0.07em;
          }

          input[type='number'] {
            width: 130px;
            padding: 0.5rem 0.7rem;
            border: 1px solid var(--border-light);
            border-radius: 7px;
            font-size: 0.9rem;
            color: var(--text-primary);
            background: var(--bg-input);
            transition: border-color 0.18s, box-shadow 0.18s;
            font-variant-numeric: tabular-nums;

            &:focus {
              outline: none;
              border-color: var(--accent);
              box-shadow: 0 0 0 3px var(--accent-glow);
            }
          }

          &.checkbox-group {
            justify-content: flex-end;

            .checkbox-label {
              display: flex;
              align-items: center;
              gap: 0.5rem;
              font-size: 0.82rem;
              font-weight: 500;
              color: var(--text-secondary);
              text-transform: none;
              letter-spacing: normal;
              cursor: pointer;
              white-space: nowrap;

              input[type='checkbox'] {
                width: 16px;
                height: 16px;
                accent-color: var(--accent);
                cursor: pointer;
              }
            }
          }
        }

        .btn {
          align-self: flex-end;
          padding: 0.55rem 1.35rem;
          border: none;
          border-radius: 7px;
          font-size: 0.88rem;
          font-weight: 600;
          cursor: pointer;
          transition: all 0.18s;

          &.btn-primary {
            background: var(--accent);
            color: #fff;

            &:hover:not(:disabled) { background: var(--accent-hover); }
            &:disabled { opacity: 0.45; cursor: not-allowed; }
          }
        }
      }

      // Tab nav
      .projection-tab-nav {
        display: flex;
        gap: 0;
        border-bottom: 1px solid var(--border);
        margin-bottom: 1.5rem;

        .tab-btn {
          padding: 0.55rem 1.25rem;
          border: none;
          background: none;
          font-size: 0.88rem;
          font-weight: 600;
          color: var(--text-muted);
          cursor: pointer;
          border-bottom: 2px solid transparent;
          margin-bottom: -1px;
          transition: color 0.18s, border-color 0.18s;

          &:hover { color: var(--accent); }

          &.active {
            color: var(--accent);
            border-bottom-color: var(--accent);
          }
        }
      }

      .tab-panel { /* intentionally bare */ }

      .projection-chart-wrapper {
        height: 380px;
        position: relative;
      }

      .projection-loading {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      // Data table
      .projection-table-wrapper {
        overflow-x: auto;
        border-radius: 7px;
        border: 1px solid var(--border);
      }

      .projection-table {
        width: 100%;
        border-collapse: collapse;
        font-size: 0.77rem;

        thead {
          background: var(--bg-elevated);
          border-bottom: 1px solid var(--border);

          th {
            padding: 0.65rem 0.9rem;
            text-align: left;
            font-weight: 600;
            color: var(--text-muted);
            white-space: nowrap;
            text-transform: uppercase;
            font-size: 0.68rem;
            letter-spacing: 0.06em;
          }
        }

        tbody tr {
          border-bottom: 1px solid var(--border);
          transition: background 0.15s;

          &:last-child { border-bottom: none; }
          &:hover { background: var(--bg-elevated); }
        }

        td {
          padding: 0.55rem 0.9rem;

          &.year-col {
            font-weight: 700;
            color: var(--accent);
          }

          &.value-col {
            font-family: 'Monaco', 'Courier New', monospace;
            text-align: right;
            color: var(--text-secondary);
          }

          &.buys-col { color: var(--accent-purple); }

          &.profit-col {
            font-weight: 600;
            &.positive { color: var(--positive); }
            &.negative { color: var(--negative); }
          }

          &.eoy-col {
            font-weight: 700;
            color: var(--text-primary);
          }

          &.inflation-col { color: #f89b29; }

          &.tax-col {
            position: relative;

            &.tax-due {
              color: var(--negative);
              font-weight: 600;
            }

            .exit-tax-badge {
              display: inline-block;
              margin-left: 0.3rem;
              padding: 0.1rem 0.3rem;
              background: var(--accent-purple);
              color: #fff;
              border-radius: 3px;
              font-size: 0.62rem;
              font-weight: 700;
              vertical-align: middle;
              cursor: help;
            }
          }

          &.after-tax-col {
            font-weight: 700;
            color: var(--accent-cyan);
          }

          &.after-tax-inflation-col {
            font-weight: 700;
            color: var(--text-secondary);
          }
        }
      }
    }

    // ── ALLOCATION SECTION ────────────────────────────────────────────────
    .allocation-section {
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      .allocation-content {
        @extend %card;
        display: flex;
        gap: 2.5rem;
        align-items: flex-start;
        padding: 1.75rem;

        .pie-wrapper {
          flex: 0 0 280px;
          height: 280px;
          position: relative;
        }

        .allocation-legend {
          flex: 1;
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(210px, 1fr));
          gap: 0.75rem;
          align-content: start;

          .legend-item {
            display: flex;
            align-items: flex-start;
            gap: 0.65rem;
            padding: 0.75rem;
            border-radius: 8px;
            background: var(--bg-surface);
            border: 1px solid var(--border);
            transition: border-color 0.18s, box-shadow 0.18s;

            &:hover {
              border-color: var(--accent);
              box-shadow: 0 0 0 1px var(--accent-glow);
            }

            .legend-color {
              flex-shrink: 0;
              width: 13px;
              height: 13px;
              border-radius: 3px;
              margin-top: 4px;
            }

            .legend-details {
              display: flex;
              flex-direction: column;
              gap: 0.15rem;
              min-width: 0;

              .legend-ticker {
                font-weight: 700;
                font-size: 0.88rem;
                color: var(--accent);
              }

              .legend-name {
                font-size: 0.74rem;
                color: var(--text-muted);
                white-space: nowrap;
                overflow: hidden;
                text-overflow: ellipsis;
              }

              .legend-metrics {
                display: flex;
                align-items: center;
                gap: 0.4rem;
                margin-top: 0.2rem;

                .legend-amount {
                  font-weight: 600;
                  font-size: 0.88rem;
                  color: var(--text-primary);
                  font-variant-numeric: tabular-nums;
                }

                .legend-percent {
                  font-size: 0.8rem;
                  color: var(--accent-purple);
                  font-weight: 600;
                  background: rgba(124, 92, 252, 0.12);
                  border-radius: 4px;
                  padding: 1px 6px;
                }
              }
            }
          }
        }
      }
    }

    // ── HOLDINGS SECTION ──────────────────────────────────────────────────
    .holdings-section {
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      // Tab nav (same pattern)
      .holdings-tab-nav {
        display: flex;
        border-bottom: 1px solid var(--border);
        margin-bottom: 1.5rem;

        .tab-btn {
          padding: 0.55rem 1.25rem;
          border: none;
          background: none;
          font-size: 0.88rem;
          font-weight: 600;
          color: var(--text-muted);
          cursor: pointer;
          border-bottom: 2px solid transparent;
          margin-bottom: -1px;
          transition: color 0.18s, border-color 0.18s;

          &:hover { color: var(--accent); }

          &.active {
            color: var(--accent);
            border-bottom-color: var(--accent);
          }
        }
      }

      // Evolution chart
      .evolution-chart-wrapper {
        height: 400px;
        position: relative;
        @extend %card;
        padding: 1.25rem;
      }

      .evolution-loading {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      .evolution-legend {
        display: flex;
        align-items: center;
        gap: 0.5rem;
        margin-top: 0.75rem;
        padding: 0 0.25rem;
        font-size: 0.82rem;
        color: var(--text-secondary);

        .legend-dot {
          display: inline-block;
          width: 11px;
          height: 11px;
          border-radius: 50%;
          flex-shrink: 0;

          &.buy-dot  { background: var(--negative); border: 2px solid #c0392b; }
          &.value-dot { background: var(--accent); margin-left: 1rem; }
        }

        .legend-label { margin-right: 0.5rem; }
      }

      // Holdings table
      .table-wrapper {
        overflow-x: auto;
        border-radius: var(--radius);
        border: 1px solid var(--border);
        background: var(--bg-card);

        .holdings-table {
          width: 100%;
          border-collapse: collapse;
          font-size: 0.88rem;

          thead {
            background: var(--bg-elevated);
            border-bottom: 1px solid var(--border);

            th {
              padding: 0.85rem 1rem;
              text-align: left;
              font-weight: 600;
              color: var(--text-muted);
              white-space: nowrap;
              text-transform: uppercase;
              font-size: 0.68rem;
              letter-spacing: 0.06em;
              border-right: 1px solid var(--border);

              &:last-child { border-right: none; }
            }

            .periods-header th {
              border-bottom: 1px solid var(--border);
              padding: 0.45rem 1rem;
              font-size: 0.65rem;
            }
          }

          tbody {
            tr.holding-row {
              border-bottom: 1px solid var(--border);
              transition: background 0.15s;
              border-left: 3px solid transparent;

              &:hover { background: var(--bg-elevated); }

              &.price-unavailable {
                border-left-color: var(--negative);
                background: var(--negative-bg);
              }

              td {
                padding: 0.85rem 1rem;
                border-right: 1px solid var(--border);

                &:last-child { border-right: none; }

                &.ticker {
                  font-weight: 700;
                  color: var(--accent);
                  font-size: 0.95rem;
                }

                &.quantity, &.price {
                  text-align: right;
                  font-family: 'Monaco', 'Courier New', monospace;
                  font-size: 0.85rem;
                  color: var(--text-secondary);
                }

                &.price-source {
                  text-align: center;
                  padding: 0.65rem 0.5rem;

                  .badge {
                    display: inline-block;
                    padding: 0.3rem 0.7rem;
                    border-radius: 12px;
                    font-size: 0.76rem;
                    font-weight: 600;
                    white-space: nowrap;
                    cursor: help;

                    &.source-Eodhd {
                      background: rgba(20, 217, 144, 0.12);
                      color: var(--positive);
                      border: 1px solid rgba(20, 217, 144, 0.25);
                    }

                    &.source-Yahoo {
                      background: rgba(79, 142, 247, 0.12);
                      color: var(--accent);
                      border: 1px solid rgba(79, 142, 247, 0.25);
                    }

                    &.source-Cache {
                      background: rgba(248, 155, 41, 0.12);
                      color: #f89b29;
                      border: 1px solid rgba(248, 155, 41, 0.25);
                    }

                    &.source-unavailable {
                      background: var(--negative-bg);
                      color: var(--negative);
                      border: 1px solid rgba(240, 82, 82, 0.25);
                    }
                  }
                }

                &.total-value {
                  text-align: right;
                  font-weight: 700;
                  color: var(--text-primary);
                  font-variant-numeric: tabular-nums;
                }

                &.positive {
                  color: var(--positive);
                  font-weight: 600;
                  background: var(--positive-bg);
                }

                &.negative {
                  color: var(--negative);
                  font-weight: 600;
                  background: var(--negative-bg);
                }

                .gain-loss {
                  display: flex;
                  flex-direction: column;
                  align-items: flex-end;
                  gap: 0.2rem;
                  font-variant-numeric: tabular-nums;

                  .percent {
                    font-size: 0.78rem;
                    opacity: 0.75;
                  }
                }

                &.actions {
                  text-align: center;

                  .btn-link {
                    background: none;
                    border: 1px solid var(--border-light);
                    color: var(--accent);
                    cursor: pointer;
                    font-weight: 600;
                    font-size: 0.8rem;
                    padding: 0.3rem 0.7rem;
                    border-radius: 6px;
                    transition: all 0.15s;

                    &:hover {
                      background: var(--accent-glow);
                      border-color: var(--accent);
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}

// ── Responsive ───────────────────────────────────────────────────────────────
@media (max-width: 768px) {
  .dashboard-container {
    padding: 1rem;

    .dashboard-content {
      .dashboard-header h1 { font-size: 1.3rem; }

      .allocation-section .allocation-content {
        flex-direction: column;
        align-items: center;

        .pie-wrapper {
          flex: 0 0 220px;
          height: 220px;
          width: 220px;
        }

        .allocation-legend {
          grid-template-columns: 1fr 1fr;
          width: 100%;
        }
      }

      .holdings-section .table-wrapper {
        font-size: 0.8rem;

        .holdings-table {
          thead th { padding: 0.6rem 0.5rem; }
          tbody td { padding: 0.6rem 0.5rem; }
        }
      }
    }
  }
}

// ── Shared helpers ──────────────────────────────────────────────────────────

// ── Top navigation bar ───────────────────────────────────────────────────────
.top-nav {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0.75rem 2.5rem;
  background: var(--bg-card);
  border-bottom: 1px solid var(--border);
  margin: -2rem -2.5rem 2rem;    // bleed to full width of .dashboard-container

  .app-brand {
    font-size: 1.05rem;
    font-weight: 700;
    color: var(--text-primary);
    letter-spacing: 0.02em;
  }

  .user-menu {
    display: flex;
    align-items: center;
    gap: 0.65rem;
  }

  .avatar {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    border: 2px solid var(--border-light);
    object-fit: cover;
  }

  .avatar-placeholder {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    background: var(--accent);
    color: #fff;
    font-size: 0.85rem;
    font-weight: 700;
    display: flex;
    align-items: center;
    justify-content: center;
  }

  .user-name {
    font-size: 0.88rem;
    color: var(--text-secondary);
    font-weight: 500;
  }

  .btn-logout {
    padding: 0.35rem 0.85rem;
    border: 1px solid var(--border-light);
    border-radius: 7px;
    background: transparent;
    color: var(--text-muted);
    font-size: 0.82rem;
    cursor: pointer;
    transition: all 0.15s;
    &:hover {
      background: var(--negative-bg);
      color: var(--negative);
      border-color: rgba(240,82,82,0.4);
    }
  }
}

%card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--shadow-md);
}

%section-heading {
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: 0.04em;
  text-transform: uppercase;
  margin-bottom: 1.25rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;

  &::before {
    content: '';
    display: inline-block;
    width: 3px;
    height: 1em;
    border-radius: 2px;
    background: var(--accent);
  }
}

// ── Dashboard shell ─────────────────────────────────────────────────────────
.dashboard-container {
  padding: 2rem 2.5rem;
  max-width: 1700px;
  margin: 0 auto;

  // Loading & error states
  .loading, .error {
    text-align: center;
    padding: 4rem 2rem;
    font-size: 1rem;
    color: var(--text-secondary);

    button {
      margin-top: 1.25rem;
      padding: 0.6rem 1.75rem;
      background: var(--accent);
      color: #fff;
      border: none;
      border-radius: 8px;
      cursor: pointer;
      font-weight: 600;
      transition: background 0.2s;

      &:hover { background: var(--accent-hover); }
    }
  }

  .error {
    @extend %card;
    color: var(--negative);
    border-color: rgba(240, 82, 82, 0.3);
    background: rgba(240, 82, 82, 0.06);
  }

  // ── Dashboard content ──────────────────────────────────────────────────────
  .dashboard-content {

    // ── HEADER ────────────────────────────────────────────────────────────────
    .dashboard-header {
      margin-bottom: 2.5rem;

      h1 {
        font-size: 1.65rem;
        font-weight: 800;
        letter-spacing: -0.03em;
        color: var(--text-primary);
        margin-bottom: 1.75rem;
        display: flex;
        align-items: center;
        gap: 0.75rem;

        &::after {
          content: '';
          flex: 1;
          height: 1px;
          background: var(--border);
        }
      }

      // Metric cards grid
      .metrics-grid {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
        gap: 1rem;
        margin-bottom: 1.5rem;

        .metric-card {
          @extend %card;
          padding: 1.35rem 1.5rem;
          position: relative;
          overflow: hidden;
          transition: transform 0.18s, box-shadow 0.18s;

          &::before {
            content: '';
            position: absolute;
            top: 0; left: 0; right: 0;
            height: 2px;
            background: var(--border-light);
            transition: background 0.2s;
          }

          &:hover {
            transform: translateY(-3px);
            box-shadow: 0 8px 28px rgba(0,0,0,0.55);
            &::before { background: var(--accent); }
          }

          .metric-label {
            font-size: 0.72rem;
            font-weight: 600;
            color: var(--text-muted);
            text-transform: uppercase;
            letter-spacing: 0.08em;
            margin-bottom: 0.65rem;
            display: flex;
            align-items: center;
            gap: 0.4rem;

            .exclamation-mark {
              display: inline-flex;
              align-items: center;
              justify-content: center;
              width: 1.15rem;
              height: 1.15rem;
              background: var(--negative);
              color: #fff;
              border-radius: 50%;
              font-size: 0.7rem;
              font-weight: 700;
              flex-shrink: 0;
            }
          }

          .metric-value {
            font-size: 1.65rem;
            font-weight: 800;
            letter-spacing: -0.03em;
            color: var(--text-primary);
            margin-bottom: 0.25rem;
            font-variant-numeric: tabular-nums;
          }

          .metric-percent {
            font-size: 0.9rem;
            font-weight: 600;
            color: var(--text-secondary);
          }

          .price-unavailable-message {
            font-size: 0.75rem;
            color: var(--negative);
            margin-top: 0.6rem;
            font-style: italic;
            background: var(--negative-bg);
            padding: 0.35rem 0.6rem;
            border-radius: 5px;
          }

          // Total Holdings – blue gradient hero card
          &.total {
            background: linear-gradient(135deg, #1a3a6e 0%, #0f224d 100%);
            border-color: rgba(79, 142, 247, 0.3);

            &::before { background: var(--accent); }

            .metric-label { color: rgba(228, 234, 245, 0.6); }
            .metric-value { color: #fff; font-size: 1.9rem; }
          }

          &.positive {
            .metric-value, .metric-percent { color: var(--positive); }
            &::before { background: var(--positive); }
          }

          &.negative {
            .metric-value, .metric-percent { color: var(--negative); }
            &::before { background: var(--negative); }
          }
        }
      }

      .action-buttons {
        display: flex;
        gap: 0.75rem;

        .btn {
          padding: 0.65rem 1.5rem;
          font-size: 0.9rem;
          border: none;
          border-radius: 8px;
          cursor: pointer;
          font-weight: 600;
          transition: all 0.18s;
          letter-spacing: 0.02em;

          &.btn-primary {
            background: var(--accent);
            color: #fff;
            box-shadow: 0 0 0 0 var(--accent-glow);

            &:hover {
              background: var(--accent-hover);
              box-shadow: 0 0 0 4px var(--accent-glow);
            }
          }
        }
      }
    }

    // ── PROJECTION SECTION ─────────────────────────────────────────────────
    .projection-section {
      @extend %card;
      padding: 1.75rem;
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      // Parameter inputs row
      .projection-params {
        display: flex;
        flex-wrap: wrap;
        align-items: flex-end;
        gap: 1rem;
        margin-bottom: 1.75rem;
        padding: 1.25rem;
        background: var(--bg-surface);
        border: 1px solid var(--border);
        border-radius: 8px;

        .param-group {
          display: flex;
          flex-direction: column;
          gap: 0.35rem;

          label {
            font-size: 0.68rem;
            font-weight: 600;
            color: var(--text-muted);
            text-transform: uppercase;
            letter-spacing: 0.07em;
          }

          input[type='number'] {
            width: 130px;
            padding: 0.5rem 0.7rem;
            border: 1px solid var(--border-light);
            border-radius: 7px;
            font-size: 0.9rem;
            color: var(--text-primary);
            background: var(--bg-input);
            transition: border-color 0.18s, box-shadow 0.18s;
            font-variant-numeric: tabular-nums;

            &:focus {
              outline: none;
              border-color: var(--accent);
              box-shadow: 0 0 0 3px var(--accent-glow);
            }
          }

          &.checkbox-group {
            justify-content: flex-end;

            .checkbox-label {
              display: flex;
              align-items: center;
              gap: 0.5rem;
              font-size: 0.82rem;
              font-weight: 500;
              color: var(--text-secondary);
              text-transform: none;
              letter-spacing: normal;
              cursor: pointer;
              white-space: nowrap;

              input[type='checkbox'] {
                width: 16px;
                height: 16px;
                accent-color: var(--accent);
                cursor: pointer;
              }
            }
          }
        }

        .btn {
          align-self: flex-end;
          padding: 0.55rem 1.35rem;
          border: none;
          border-radius: 7px;
          font-size: 0.88rem;
          font-weight: 600;
          cursor: pointer;
          transition: all 0.18s;

          &.btn-primary {
            background: var(--accent);
            color: #fff;

            &:hover:not(:disabled) { background: var(--accent-hover); }
            &:disabled { opacity: 0.45; cursor: not-allowed; }
          }
        }
      }

      // Tab nav
      .projection-tab-nav {
        display: flex;
        gap: 0;
        border-bottom: 1px solid var(--border);
        margin-bottom: 1.5rem;

        .tab-btn {
          padding: 0.55rem 1.25rem;
          border: none;
          background: none;
          font-size: 0.88rem;
          font-weight: 600;
          color: var(--text-muted);
          cursor: pointer;
          border-bottom: 2px solid transparent;
          margin-bottom: -1px;
          transition: color 0.18s, border-color 0.18s;

          &:hover { color: var(--accent); }

          &.active {
            color: var(--accent);
            border-bottom-color: var(--accent);
          }
        }
      }

      .tab-panel { /* intentionally bare */ }

      .projection-chart-wrapper {
        height: 380px;
        position: relative;
      }

      .projection-loading {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      // Data table
      .projection-table-wrapper {
        overflow-x: auto;
        border-radius: 7px;
        border: 1px solid var(--border);
      }

      .projection-table {
        width: 100%;
        border-collapse: collapse;
        font-size: 0.77rem;

        thead {
          background: var(--bg-elevated);
          border-bottom: 1px solid var(--border);

          th {
            padding: 0.65rem 0.9rem;
            text-align: left;
            font-weight: 600;
            color: var(--text-muted);
            white-space: nowrap;
            text-transform: uppercase;
            font-size: 0.68rem;
            letter-spacing: 0.06em;
          }
        }

        tbody tr {
          border-bottom: 1px solid var(--border);
          transition: background 0.15s;

          &:last-child { border-bottom: none; }
          &:hover { background: var(--bg-elevated); }
        }

        td {
          padding: 0.55rem 0.9rem;

          &.year-col {
            font-weight: 700;
            color: var(--accent);
          }

          &.value-col {
            font-family: 'Monaco', 'Courier New', monospace;
            text-align: right;
            color: var(--text-secondary);
          }

          &.buys-col { color: var(--accent-purple); }

          &.profit-col {
            font-weight: 600;
            &.positive { color: var(--positive); }
            &.negative { color: var(--negative); }
          }

          &.eoy-col {
            font-weight: 700;
            color: var(--text-primary);
          }

          &.inflation-col { color: #f89b29; }

          &.tax-col {
            position: relative;

            &.tax-due {
              color: var(--negative);
              font-weight: 600;
            }

            .exit-tax-badge {
              display: inline-block;
              margin-left: 0.3rem;
              padding: 0.1rem 0.3rem;
              background: var(--accent-purple);
              color: #fff;
              border-radius: 3px;
              font-size: 0.62rem;
              font-weight: 700;
              vertical-align: middle;
              cursor: help;
            }
          }

          &.after-tax-col {
            font-weight: 700;
            color: var(--accent-cyan);
          }

          &.after-tax-inflation-col {
            font-weight: 700;
            color: var(--text-secondary);
          }
        }
      }
    }

    // ── ALLOCATION SECTION ────────────────────────────────────────────────
    .allocation-section {
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      .allocation-content {
        @extend %card;
        display: flex;
        gap: 2.5rem;
        align-items: flex-start;
        padding: 1.75rem;

        .pie-wrapper {
          flex: 0 0 280px;
          height: 280px;
          position: relative;
        }

        .allocation-legend {
          flex: 1;
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(210px, 1fr));
          gap: 0.75rem;
          align-content: start;

          .legend-item {
            display: flex;
            align-items: flex-start;
            gap: 0.65rem;
            padding: 0.75rem;
            border-radius: 8px;
            background: var(--bg-surface);
            border: 1px solid var(--border);
            transition: border-color 0.18s, box-shadow 0.18s;

            &:hover {
              border-color: var(--accent);
              box-shadow: 0 0 0 1px var(--accent-glow);
            }

            .legend-color {
              flex-shrink: 0;
              width: 13px;
              height: 13px;
              border-radius: 3px;
              margin-top: 4px;
            }

            .legend-details {
              display: flex;
              flex-direction: column;
              gap: 0.15rem;
              min-width: 0;

              .legend-ticker {
                font-weight: 700;
                font-size: 0.88rem;
                color: var(--accent);
              }

              .legend-name {
                font-size: 0.74rem;
                color: var(--text-muted);
                white-space: nowrap;
                overflow: hidden;
                text-overflow: ellipsis;
              }

              .legend-metrics {
                display: flex;
                align-items: center;
                gap: 0.4rem;
                margin-top: 0.2rem;

                .legend-amount {
                  font-weight: 600;
                  font-size: 0.88rem;
                  color: var(--text-primary);
                  font-variant-numeric: tabular-nums;
                }

                .legend-percent {
                  font-size: 0.8rem;
                  color: var(--accent-purple);
                  font-weight: 600;
                  background: rgba(124, 92, 252, 0.12);
                  border-radius: 4px;
                  padding: 1px 6px;
                }
              }
            }
          }
        }
      }
    }

    // ── HOLDINGS SECTION ──────────────────────────────────────────────────
    .holdings-section {
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      // Tab nav (same pattern)
      .holdings-tab-nav {
        display: flex;
        border-bottom: 1px solid var(--border);
        margin-bottom: 1.5rem;

        .tab-btn {
          padding: 0.55rem 1.25rem;
          border: none;
          background: none;
          font-size: 0.88rem;
          font-weight: 600;
          color: var(--text-muted);
          cursor: pointer;
          border-bottom: 2px solid transparent;
          margin-bottom: -1px;
          transition: color 0.18s, border-color 0.18s;

          &:hover { color: var(--accent); }

          &.active {
            color: var(--accent);
            border-bottom-color: var(--accent);
          }
        }
      }

      // Evolution chart
      .evolution-chart-wrapper {
        height: 400px;
        position: relative;
        @extend %card;
        padding: 1.25rem;
      }

      .evolution-loading {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      .evolution-legend {
        display: flex;
        align-items: center;
        gap: 0.5rem;
        margin-top: 0.75rem;
        padding: 0 0.25rem;
        font-size: 0.82rem;
        color: var(--text-secondary);

        .legend-dot {
          display: inline-block;
          width: 11px;
          height: 11px;
          border-radius: 50%;
          flex-shrink: 0;

          &.buy-dot  { background: var(--negative); border: 2px solid #c0392b; }
          &.value-dot { background: var(--accent); margin-left: 1rem; }
        }

        .legend-label { margin-right: 0.5rem; }
      }

      // Holdings table
      .table-wrapper {
        overflow-x: auto;
        border-radius: var(--radius);
        border: 1px solid var(--border);
        background: var(--bg-card);

        .holdings-table {
          width: 100%;
          border-collapse: collapse;
          font-size: 0.88rem;

          thead {
            background: var(--bg-elevated);
            border-bottom: 1px solid var(--border);

            th {
              padding: 0.85rem 1rem;
              text-align: left;
              font-weight: 600;
              color: var(--text-muted);
              white-space: nowrap;
              text-transform: uppercase;
              font-size: 0.68rem;
              letter-spacing: 0.06em;
              border-right: 1px solid var(--border);

              &:last-child { border-right: none; }
            }

            .periods-header th {
              border-bottom: 1px solid var(--border);
              padding: 0.45rem 1rem;
              font-size: 0.65rem;
            }
          }

          tbody {
            tr.holding-row {
              border-bottom: 1px solid var(--border);
              transition: background 0.15s;
              border-left: 3px solid transparent;

              &:hover { background: var(--bg-elevated); }

              &.price-unavailable {
                border-left-color: var(--negative);
                background: var(--negative-bg);
              }

              td {
                padding: 0.85rem 1rem;
                border-right: 1px solid var(--border);

                &:last-child { border-right: none; }

                &.ticker {
                  font-weight: 700;
                  color: var(--accent);
                  font-size: 0.95rem;
                }

                &.quantity, &.price {
                  text-align: right;
                  font-family: 'Monaco', 'Courier New', monospace;
                  font-size: 0.85rem;
                  color: var(--text-secondary);
                }

                &.price-source {
                  text-align: center;
                  padding: 0.65rem 0.5rem;

                  .badge {
                    display: inline-block;
                    padding: 0.3rem 0.7rem;
                    border-radius: 12px;
                    font-size: 0.76rem;
                    font-weight: 600;
                    white-space: nowrap;
                    cursor: help;

                    &.source-Eodhd {
                      background: rgba(20, 217, 144, 0.12);
                      color: var(--positive);
                      border: 1px solid rgba(20, 217, 144, 0.25);
                    }

                    &.source-Yahoo {
                      background: rgba(79, 142, 247, 0.12);
                      color: var(--accent);
                      border: 1px solid rgba(79, 142, 247, 0.25);
                    }

                    &.source-Cache {
                      background: rgba(248, 155, 41, 0.12);
                      color: #f89b29;
                      border: 1px solid rgba(248, 155, 41, 0.25);
                    }

                    &.source-unavailable {
                      background: var(--negative-bg);
                      color: var(--negative);
                      border: 1px solid rgba(240, 82, 82, 0.25);
                    }
                  }
                }

                &.total-value {
                  text-align: right;
                  font-weight: 700;
                  color: var(--text-primary);
                  font-variant-numeric: tabular-nums;
                }

                &.positive {
                  color: var(--positive);
                  font-weight: 600;
                  background: var(--positive-bg);
                }

                &.negative {
                  color: var(--negative);
                  font-weight: 600;
                  background: var(--negative-bg);
                }

                .gain-loss {
                  display: flex;
                  flex-direction: column;
                  align-items: flex-end;
                  gap: 0.2rem;
                  font-variant-numeric: tabular-nums;

                  .percent {
                    font-size: 0.78rem;
                    opacity: 0.75;
                  }
                }

                &.actions {
                  text-align: center;

                  .btn-link {
                    background: none;
                    border: 1px solid var(--border-light);
                    color: var(--accent);
                    cursor: pointer;
                    font-weight: 600;
                    font-size: 0.8rem;
                    padding: 0.3rem 0.7rem;
                    border-radius: 6px;
                    transition: all 0.15s;

                    &:hover {
                      background: var(--accent-glow);
                      border-color: var(--accent);
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}

// ── Responsive ───────────────────────────────────────────────────────────────
@media (max-width: 768px) {
  .dashboard-container {
    padding: 1rem;

    .dashboard-content {
      .dashboard-header h1 { font-size: 1.3rem; }

      .allocation-section .allocation-content {
        flex-direction: column;
        align-items: center;

        .pie-wrapper {
          flex: 0 0 220px;
          height: 220px;
          width: 220px;
        }

        .allocation-legend {
          grid-template-columns: 1fr 1fr;
          width: 100%;
        }
      }

      .holdings-section .table-wrapper {
        font-size: 0.8rem;

        .holdings-table {
          thead th { padding: 0.6rem 0.5rem; }
          tbody td { padding: 0.6rem 0.5rem; }
        }
      }
    }
  }
}

import { Component, OnInit, OnDestroy, AfterViewChecked, ChangeDetectionStrategy, ChangeDetectorRef, ElementRef, ViewChild } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ApiService, DashboardDto, HoldingDto, ProjectionResultDto, ProjectionSettingsDto, PortfolioEvolutionDto } from '../../services/api.service';
import { AddTransactionModalComponent } from '../../components/add-transaction-modal/add-transaction-modal.component';
import { BuyHistoryModalComponent } from '../../components/buy-history-modal/buy-history-modal.component';
import {
  Chart, ArcElement, Tooltip, Legend, PieController,
  LineController, LineElement, PointElement, LinearScale, CategoryScale, Filler,
  type ChartData
} from 'chart.js';

Chart.register(ArcElement, Tooltip, Legend, PieController, LineController, LineElement, PointElement, LinearScale, CategoryScale, Filler);

const PIE_COLORS = [
  '#4f8ef7', '#7c5cfc', '#06d6d0', '#14d990', '#f89b29',
  '#f05252', '#fa709a', '#a78bfa', '#34d399', '#fbbf24',
  '#60a5fa', '#c084fc', '#2dd4bf', '#86efac', '#fcd34d',
];

// Shared dark-theme Chart.js defaults
const DARK_SCALE_DEFAULTS = {
  grid:  { color: 'rgba(31, 46, 74, 0.8)' },
  ticks: { color: '#8da0bf' },
  title: { color: '#8da0bf' },
  border: { color: 'rgba(31,46,74,0.5)' },
};

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule, FormsModule, AddTransactionModalComponent, BuyHistoryModalComponent],
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class DashboardComponent implements OnInit, OnDestroy, AfterViewChecked {
  dashboard: DashboardDto | null = null;
  loading = true;
  error: string | null = null;

  showAddTransactionModal = false;
  showBuyHistoryModal = false;
  selectedHoldingId: number | null = null;

  @ViewChild('allocationChart') allocationChartRef!: ElementRef<HTMLCanvasElement>;
  private pieChart: Chart | null = null;
  private chartRendered = false;

  // Projection
  projection: ProjectionResultDto | null = null;
  projectionSettings: ProjectionSettingsDto = {
    yearlyReturnPercent: 7,
    monthlyBuyAmount: 500,
    annualBuyIncreasePercent: 3,
    projectionYears: 10,
    inflationPercent: 2,
    cgtPercent: 38,
    exitTaxPercent: 38,
    excludePreExistingFromTax: false,
  };
  projectionLoading = false;
  projectionSaving = false;
  activeProjectionTab: 'chart' | 'table' = 'chart';
  currentYear = new Date().getFullYear();

  @ViewChild('projectionChart') projectionChartRef!: ElementRef<HTMLCanvasElement>;
  private lineChart: Chart | null = null;
  private projectionChartRendered = false;

  // Holdings tabs
  activeHoldingsTab: 'table' | 'evolution' = 'table';
  portfolioEvolution: PortfolioEvolutionDto | null = null;
  evolutionLoading = false;

  @ViewChild('evolutionChart') evolutionChartRef!: ElementRef<HTMLCanvasElement>;
  private evolutionChart: Chart | null = null;
  private evolutionChartRendered = false;

  get allocationSlices(): { ticker: string; etfName: string; value: number; percent: number; color: string }[] {
    if (!this.dashboard?.holdings?.length) return [];
    const total = this.dashboard.holdings.reduce((sum, h) => sum + h.totalValue, 0);
    return this.dashboard.holdings.map((h, i) => ({
      ticker: h.ticker,
      etfName: h.etfName,
      value: h.totalValue,
      percent: total > 0 ? (h.totalValue / total) * 100 : 0,
      color: PIE_COLORS[i % PIE_COLORS.length],
    }));
  }

  constructor(private apiService: ApiService, private cdr: ChangeDetectorRef) {}

  ngOnInit(): void {
    console.log('Dashboard component initialized');
    this.loadDashboard();
    this.loadProjection();
    this.loadPortfolioEvolution();
  }

  ngAfterViewChecked(): void {
    if (this.dashboard && !this.loading && !this.chartRendered && this.allocationChartRef?.nativeElement) {
      this.chartRendered = true;
      this.renderPieChart();
    }
    if (this.projection && !this.projectionLoading && !this.projectionChartRendered && this.projectionChartRef?.nativeElement) {
      this.projectionChartRendered = true;
      this.renderLineChart();
    }
    if (this.portfolioEvolution && !this.evolutionLoading && !this.evolutionChartRendered && this.evolutionChartRef?.nativeElement) {
      this.evolutionChartRendered = true;
      this.renderEvolutionChart();
    }
  }

  ngOnDestroy(): void {
    this.pieChart?.destroy();
    this.lineChart?.destroy();
    this.evolutionChart?.destroy();
  }

  private renderPieChart(): void {
    this.pieChart?.destroy();
    const slices = this.allocationSlices;
    if (!slices.length) return;

    const ctx = this.allocationChartRef.nativeElement.getContext('2d');
    if (!ctx) return;

    this.pieChart = new Chart(ctx, {
      type: 'pie',
      data: {
        labels: slices.map(s => s.ticker),
        datasets: [{
          data: slices.map(s => s.value),
          backgroundColor: slices.map(s => s.color),
          borderWidth: 2,
          borderColor: '#111d35',
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: {
            backgroundColor: '#172040',
            borderColor: '#1f2e4a',
            borderWidth: 1,
            titleColor: '#e4eaf5',
            bodyColor: '#8da0bf',
            callbacks: {
              label: (ctx) => {
                const slice = slices[ctx.dataIndex];
                return ` ${slice.ticker}: ${this.formatCurrency(slice.value)} (${slice.percent.toFixed(1)}%)`;
              }
            }
          }
        }
      }
    });
  }

  private renderLineChart(): void {
    this.lineChart?.destroy();
    const points = this.projection?.dataPoints;
    if (!points?.length) return;

    const ctx = this.projectionChartRef.nativeElement.getContext('2d');
    if (!ctx) return;

    this.lineChart = new Chart(ctx, {
      type: 'line',
      data: {
        labels: points.map(p => p.year.toString()),
        datasets: [
          {
            label: 'Projected Portfolio Value',
            data: points.map(p => p.totalAmount),
            borderColor: '#4f8ef7',
            backgroundColor: 'rgba(79, 142, 247, 0.10)',
            fill: true,
            tension: 0.35,
            pointRadius: 5,
            pointHoverRadius: 7,
            pointBackgroundColor: '#4f8ef7',
          },
          {
            label: 'Amount corrected by inflation',
            data: points.map(p => p.inflationCorrectedAmount),
            borderColor: '#f05252',
            backgroundColor: 'rgba(240, 82, 82, 0.07)',
            fill: true,
            tension: 0.35,
            pointRadius: 5,
            pointHoverRadius: 7,
            pointBackgroundColor: '#f05252',
            borderDash: [6, 3],
          },
          {
            label: 'Projected after taxes',
            data: points.map(p => p.afterTaxTotalAmount),
            borderColor: '#4d6080',
            backgroundColor: 'rgba(77, 96, 128, 0.06)',
            fill: false,
            tension: 0.35,
            pointRadius: 5,
            pointHoverRadius: 7,
            pointBackgroundColor: '#4d6080',
            borderDash: [4, 4],
          },
          {
            label: 'After Tax Balance Inflation-Corrected',
            data: points.map(p => p.afterTaxInflationCorrectedAmount),
            borderColor: '#f89b29',
            backgroundColor: 'rgba(248, 155, 41, 0.07)',
            fill: false,
            tension: 0.35,
            pointRadius: 5,
            pointHoverRadius: 7,
            pointBackgroundColor: '#f89b29',
            borderDash: [8, 3],
          }
        ]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        scales: {
          x: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Year', font: { weight: 'bold' }, color: '#8da0bf' }
          },
          y: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Total Value (€)', font: { weight: 'bold' }, color: '#8da0bf' },
            ticks: {
              color: '#8da0bf',
              callback: (value) => `€${Number(value).toLocaleString('de-IE', { maximumFractionDigits: 0 })}`
            }
          }
        },
        plugins: {
          legend: {
            display: true,
            position: 'top',
            labels: { usePointStyle: true, padding: 20, color: '#8da0bf' }
          },
          tooltip: {
            backgroundColor: '#172040',
            borderColor: '#1f2e4a',
            borderWidth: 1,
            titleColor: '#e4eaf5',
            bodyColor: '#8da0bf',
            callbacks: {
              label: (tooltipCtx) => ` ${tooltipCtx.dataset.label}: ${this.formatCurrency(tooltipCtx.parsed.y as number)}`
            }
          }
        }
      }
    });
  }

  loadProjection(): void {
    this.projectionLoading = true;
    this.projectionChartRendered = false;
    this.lineChart?.destroy();
    this.lineChart = null;
    this.apiService.getProjection().subscribe({
      next: (data) => {
        this.projection = data;
        this.projectionSettings = { ...data.settings };
        this.projectionLoading = false;
        this.cdr.markForCheck();
      },
      error: (err) => {
        console.error('Error loading projection:', err);
        this.projectionLoading = false;
        this.cdr.markForCheck();
      }
    });
  }

  saveProjectionSettings(): void {
    this.projectionSaving = true;
    this.apiService.saveProjectionSettings(this.projectionSettings).subscribe({
      next: () => {
        this.projectionSaving = false;
        // Reload projection with new settings
        this.projectionChartRendered = false;
        this.lineChart?.destroy();
        this.lineChart = null;
        this.loadProjection();
      },
      error: (err) => {
        console.error('Error saving projection settings:', err);
        this.projectionSaving = false;
        this.cdr.markForCheck();
      }
    });
  }

  setProjectionTab(tab: 'chart' | 'table'): void {
    this.activeProjectionTab = tab;
    if (tab === 'chart') {
      this.projectionChartRendered = false;
      this.lineChart?.destroy();
      this.lineChart = null;
    }
    this.cdr.markForCheck();
  }

  private renderEvolutionChart(): void {
    this.evolutionChart?.destroy();
    const points = this.portfolioEvolution?.dataPoints;
    if (!points?.length) return;

    const ctx = this.evolutionChartRef.nativeElement.getContext('2d');
    if (!ctx) return;

    // Build per-point arrays for dynamic point styling
    const pointRadii = points.map(p => (p.hasBuy ? 8 : 3));
    const pointColors = points.map(p => (p.hasBuy ? '#f05252' : '#4f8ef7'));
    const pointBorderColors = points.map(p => (p.hasBuy ? '#c0392b' : '#4f8ef7'));
    const pointBorderWidths = points.map(p => (p.hasBuy ? 2 : 1));
    const pointHoverRadii = points.map(p => (p.hasBuy ? 10 : 5));

    this.evolutionChart = new Chart(ctx, {
      type: 'line',
      data: {
        labels: points.map(p => p.date),
        datasets: [
          {
            label: 'Portfolio Value',
            data: points.map(p => p.totalValue),
            borderColor: '#4f8ef7',
            backgroundColor: 'rgba(79, 142, 247, 0.08)',
            fill: true,
            tension: 0.25,
            pointRadius: pointRadii,
            pointHoverRadius: pointHoverRadii,
            pointBackgroundColor: pointColors,
            pointBorderColor: pointBorderColors,
            pointBorderWidth: pointBorderWidths,
          }
        ]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        interaction: { mode: 'index', intersect: false },
        scales: {
          x: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Date', font: { weight: 'bold' }, color: '#8da0bf' },
            ticks: {
              color: '#8da0bf',
              maxTicksLimit: 20,
              maxRotation: 45,
            }
          },
          y: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Total Value (€)', font: { weight: 'bold' }, color: '#8da0bf' },
            ticks: {
              color: '#8da0bf',
              callback: (value) => `€${Number(value).toLocaleString('de-IE', { maximumFractionDigits: 0 })}`
            }
          }
        },
        plugins: {
          legend: { display: false },
          tooltip: {
            backgroundColor: '#172040',
            borderColor: '#1f2e4a',
            borderWidth: 1,
            titleColor: '#e4eaf5',
            bodyColor: '#8da0bf',
            callbacks: {
              title: (items) => {
                const idx = items[0].dataIndex;
                const pt = points[idx];
                return pt.hasBuy ? `${pt.date}   Buy recorded` : pt.date;
              },
              label: (tooltipCtx) =>
                ` Portfolio: ${this.formatCurrency(tooltipCtx.parsed.y as number)}`
            }
          }
        }
      }
    });
  }

  loadPortfolioEvolution(): void {
    this.evolutionLoading = true;
    this.evolutionChartRendered = false;
    this.evolutionChart?.destroy();
    this.evolutionChart = null;
    this.apiService.getPortfolioEvolution().subscribe({
      next: (data) => {
        this.portfolioEvolution = data;
        this.evolutionLoading = false;
        this.cdr.markForCheck();
      },
      error: (err) => {
        console.error('Error loading portfolio evolution:', err);
        this.evolutionLoading = false;
        this.cdr.markForCheck();
      }
    });
  }

  setHoldingsTab(tab: 'table' | 'evolution'): void {
    this.activeHoldingsTab = tab;
    if (tab === 'evolution') {
      this.evolutionChartRendered = false;
      this.evolutionChart?.destroy();
      this.evolutionChart = null;
    }
    this.cdr.markForCheck();
  }

  loadDashboard(): void {
    console.log('Loading dashboard...');
    this.loading = true;
    this.error = null;
    this.chartRendered = false;
    this.pieChart?.destroy();
    this.pieChart = null;
    this.apiService.getDashboard().subscribe({
      next: (data: DashboardDto) => {
        console.log('Dashboard data received:', data);
        this.dashboard = data;
        this.loading = false;
        this.cdr.markForCheck();
      },
      error: (err: any) => {
        console.error('Error loading dashboard:', err);
        this.error = 'Failed to load dashboard. Please ensure the API is running.';
        this.loading = false;
        this.cdr.markForCheck();
      }
    });
  }

  formatCurrency(value: number): string {
    return new Intl.NumberFormat('de-IE', {
      style: 'currency',
      currency: 'EUR',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    }).format(value);
  }

  formatPercent(value: number): string {
    return value >= 0 ? `+${value.toFixed(2)}%` : `${value.toFixed(2)}%`;
  }

  formatQuantity(value: number): string {
    return value.toFixed(4);
  }

  getMetricsClass(gainLossEur: number): string {
    return gainLossEur >= 0 ? 'positive' : 'negative';
  }

  onAddTransactionClick(): void {
    this.showAddTransactionModal = true;
  }

  onTransactionAdded(): void {
    this.showAddTransactionModal = false;
    this.loadDashboard();
  }

  onTransactionCancelled(): void {
    this.showAddTransactionModal = false;
  }

  onBuyHistoryClick(holdingId: number): void {
    this.selectedHoldingId = holdingId;
    this.showBuyHistoryModal = true;
  }

  onHistoryModalClosed(): void {
    this.showBuyHistoryModal = false;
    this.selectedHoldingId = null;
  }

  getPriceSourceLabel(source: string | null): string {
    if (!source) return 'N/A';
    const labels: { [key: string]: string } = {
      'Eodhd': 'Eodhd',
      'Yahoo': 'Yahoo',
      'Cache': 'Cached'
    };
    return labels[source] || 'Unknown';
  }

  getPriceSourceDescription(source: string | null): string {
    if (!source) return 'Price data unavailable';
    const descriptions: { [key: string]: string } = {
      'Eodhd': 'Real-time price from Eodhd API (Premium)',
      'Yahoo': 'Real-time price from Yahoo Finance',
      'Cache': 'Cached price from last update'
    };
    return descriptions[source] || 'Unknown source';
  }

}

import { Component, OnInit, OnDestroy, AfterViewChecked, ChangeDetectionStrategy, ChangeDetectorRef, ElementRef, ViewChild } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ApiService, DashboardDto, HoldingDto, ProjectionResultDto, ProjectionSettingsDto, PortfolioEvolutionDto } from '../../services/api.service';
import { AuthService, CurrentUser } from '../../services/auth.service';
import { AddTransactionModalComponent } from '../../components/add-transaction-modal/add-transaction-modal.component';
import { BuyHistoryModalComponent } from '../../components/buy-history-modal/buy-history-modal.component';
import {
  Chart, ArcElement, Tooltip, Legend, PieController,
  LineController, LineElement, PointElement, LinearScale, CategoryScale, Filler,
  type ChartData
} from 'chart.js';

Chart.register(ArcElement, Tooltip, Legend, PieController, LineController, LineElement, PointElement, LinearScale, CategoryScale, Filler);

const PIE_COLORS = [
  '#4f8ef7', '#7c5cfc', '#06d6d0', '#14d990', '#f89b29',
  '#f05252', '#fa709a', '#a78bfa', '#34d399', '#fbbf24',
  '#60a5fa', '#c084fc', '#2dd4bf', '#86efac', '#fcd34d',
];

// Shared dark-theme Chart.js defaults
const DARK_SCALE_DEFAULTS = {
  grid:  { color: 'rgba(31, 46, 74, 0.8)' },
  ticks: { color: '#8da0bf' },
  title: { color: '#8da0bf' },
  border: { color: 'rgba(31,46,74,0.5)' },
};

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule, FormsModule, AddTransactionModalComponent, BuyHistoryModalComponent],
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class DashboardComponent implements OnInit, OnDestroy, AfterViewChecked {
  dashboard: DashboardDto | null = null;
  loading = true;
  error: string | null = null;

  showAddTransactionModal = false;
  showBuyHistoryModal = false;
  selectedHoldingId: number | null = null;

  @ViewChild('allocationChart') allocationChartRef!: ElementRef<HTMLCanvasElement>;
  private pieChart: Chart | null = null;
  private chartRendered = false;

  // Projection
  projection: ProjectionResultDto | null = null;
  projectionSettings: ProjectionSettingsDto = {
    yearlyReturnPercent: 7,
    monthlyBuyAmount: 500,
    annualBuyIncreasePercent: 3,
    projectionYears: 10,
    inflationPercent: 2,
    cgtPercent: 38,
    exitTaxPercent: 38,
    excludePreExistingFromTax: false,
  };
  projectionLoading = false;
  projectionSaving = false;
  activeProjectionTab: 'chart' | 'table' = 'chart';
  currentYear = new Date().getFullYear();

  @ViewChild('projectionChart') projectionChartRef!: ElementRef<HTMLCanvasElement>;
  private lineChart: Chart | null = null;
  private projectionChartRendered = false;

  // Holdings tabs
  activeHoldingsTab: 'table' | 'evolution' = 'table';
  portfolioEvolution: PortfolioEvolutionDto | null = null;
  evolutionLoading = false;

  @ViewChild('evolutionChart') evolutionChartRef!: ElementRef<HTMLCanvasElement>;
  private evolutionChart: Chart | null = null;
  private evolutionChartRendered = false;

  get allocationSlices(): { ticker: string; etfName: string; value: number; percent: number; color: string }[] {
    if (!this.dashboard?.holdings?.length) return [];
    const total = this.dashboard.holdings.reduce((sum, h) => sum + h.totalValue, 0);
    return this.dashboard.holdings.map((h, i) => ({
      ticker: h.ticker,
      etfName: h.etfName,
      value: h.totalValue,
      percent: total > 0 ? (h.totalValue / total) * 100 : 0,
      color: PIE_COLORS[i % PIE_COLORS.length],
    }));
  }

  constructor(private apiService: ApiService, private cdr: ChangeDetectorRef, public auth: AuthService) {}

  ngOnInit(): void {
    console.log('Dashboard component initialized');
    this.loadDashboard();
    this.loadProjection();
    this.loadPortfolioEvolution();
  }

  ngAfterViewChecked(): void {
    if (this.dashboard && !this.loading && !this.chartRendered && this.allocationChartRef?.nativeElement) {
      this.chartRendered = true;
      this.renderPieChart();
    }
    if (this.projection && !this.projectionLoading && !this.projectionChartRendered && this.projectionChartRef?.nativeElement) {
      this.projectionChartRendered = true;
      this.renderLineChart();
    }
    if (this.portfolioEvolution && !this.evolutionLoading && !this.evolutionChartRendered && this.evolutionChartRef?.nativeElement) {
      this.evolutionChartRendered = true;
      this.renderEvolutionChart();
    }
  }

  ngOnDestroy(): void {
    this.pieChart?.destroy();
    this.lineChart?.destroy();
    this.evolutionChart?.destroy();
  }

  private renderPieChart(): void {
    this.pieChart?.destroy();
    const slices = this.allocationSlices;
    if (!slices.length) return;

    const ctx = this.allocationChartRef.nativeElement.getContext('2d');
    if (!ctx) return;

    this.pieChart = new Chart(ctx, {
      type: 'pie',
      data: {
        labels: slices.map(s => s.ticker),
        datasets: [{
          data: slices.map(s => s.value),
          backgroundColor: slices.map(s => s.color),
          borderWidth: 2,
          borderColor: '#111d35',
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: {
            backgroundColor: '#172040',
            borderColor: '#1f2e4a',
            borderWidth: 1,
            titleColor: '#e4eaf5',
            bodyColor: '#8da0bf',
            callbacks: {
              label: (ctx) => {
                const slice = slices[ctx.dataIndex];
                return ` ${slice.ticker}: ${this.formatCurrency(slice.value)} (${slice.percent.toFixed(1)}%)`;
              }
            }
          }
        }
      }
    });
  }

  private renderLineChart(): void {
    this.lineChart?.destroy();
    const points = this.projection?.dataPoints;
    if (!points?.length) return;

    const ctx = this.projectionChartRef.nativeElement.getContext('2d');
    if (!ctx) return;

    this.lineChart = new Chart(ctx, {
      type: 'line',
      data: {
        labels: points.map(p => p.year.toString()),
        datasets: [
          {
            label: 'Projected Portfolio Value',
            data: points.map(p => p.totalAmount),
            borderColor: '#4f8ef7',
            backgroundColor: 'rgba(79, 142, 247, 0.10)',
            fill: true,
            tension: 0.35,
            pointRadius: 5,
            pointHoverRadius: 7,
            pointBackgroundColor: '#4f8ef7',
          },
          {
            label: 'Amount corrected by inflation',
            data: points.map(p => p.inflationCorrectedAmount),
            borderColor: '#f05252',
            backgroundColor: 'rgba(240, 82, 82, 0.07)',
            fill: true,
            tension: 0.35,
            pointRadius: 5,
            pointHoverRadius: 7,
            pointBackgroundColor: '#f05252',
            borderDash: [6, 3],
          },
          {
            label: 'Projected after taxes',
            data: points.map(p => p.afterTaxTotalAmount),
            borderColor: '#4d6080',
            backgroundColor: 'rgba(77, 96, 128, 0.06)',
            fill: false,
            tension: 0.35,
            pointRadius: 5,
            pointHoverRadius: 7,
            pointBackgroundColor: '#4d6080',
            borderDash: [4, 4],
          },
          {
            label: 'After Tax Balance Inflation-Corrected',
            data: points.map(p => p.afterTaxInflationCorrectedAmount),
            borderColor: '#f89b29',
            backgroundColor: 'rgba(248, 155, 41, 0.07)',
            fill: false,
            tension: 0.35,
            pointRadius: 5,
            pointHoverRadius: 7,
            pointBackgroundColor: '#f89b29',
            borderDash: [8, 3],
          }
        ]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        scales: {
          x: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Year', font: { weight: 'bold' }, color: '#8da0bf' }
          },
          y: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Total Value (€)', font: { weight: 'bold' }, color: '#8da0bf' },
            ticks: {
              color: '#8da0bf',
              callback: (value) => `€${Number(value).toLocaleString('de-IE', { maximumFractionDigits: 0 })}`
            }
          }
        },
        plugins: {
          legend: {
            display: true,
            position: 'top',
            labels: { usePointStyle: true, padding: 20, color: '#8da0bf' }
          },
          tooltip: {
            backgroundColor: '#172040',
            borderColor: '#1f2e4a',
            borderWidth: 1,
            titleColor: '#e4eaf5',
            bodyColor: '#8da0bf',
            callbacks: {
              label: (tooltipCtx) => ` ${tooltipCtx.dataset.label}: ${this.formatCurrency(tooltipCtx.parsed.y as number)}`
            }
          }
        }
      }
    });
  }

  loadProjection(): void {
    this.projectionLoading = true;
    this.projectionChartRendered = false;
    this.lineChart?.destroy();
    this.lineChart = null;
    this.apiService.getProjection().subscribe({
      next: (data) => {
        this.projection = data;
        this.projectionSettings = { ...data.settings };
        this.projectionLoading = false;
        this.cdr.markForCheck();
      },
      error: (err) => {
        console.error('Error loading projection:', err);
        this.projectionLoading = false;
        this.cdr.markForCheck();
      }
    });
  }

  saveProjectionSettings(): void {
    this.projectionSaving = true;
    this.apiService.saveProjectionSettings(this.projectionSettings).subscribe({
      next: () => {
        this.projectionSaving = false;
        // Reload projection with new settings
        this.projectionChartRendered = false;
        this.lineChart?.destroy();
        this.lineChart = null;
        this.loadProjection();
      },
      error: (err) => {
        console.error('Error saving projection settings:', err);
        this.projectionSaving = false;
        this.cdr.markForCheck();
      }
    });
  }

  setProjectionTab(tab: 'chart' | 'table'): void {
    this.activeProjectionTab = tab;
    if (tab === 'chart') {
      this.projectionChartRendered = false;
      this.lineChart?.destroy();
      this.lineChart = null;
    }
    this.cdr.markForCheck();
  }

  private renderEvolutionChart(): void {
    this.evolutionChart?.destroy();
    const points = this.portfolioEvolution?.dataPoints;
    if (!points?.length) return;

    const ctx = this.evolutionChartRef.nativeElement.getContext('2d');
    if (!ctx) return;

    // Build per-point arrays for dynamic point styling
    const pointRadii = points.map(p => (p.hasBuy ? 8 : 3));
    const pointColors = points.map(p => (p.hasBuy ? '#f05252' : '#4f8ef7'));
    const pointBorderColors = points.map(p => (p.hasBuy ? '#c0392b' : '#4f8ef7'));
    const pointBorderWidths = points.map(p => (p.hasBuy ? 2 : 1));
    const pointHoverRadii = points.map(p => (p.hasBuy ? 10 : 5));

    this.evolutionChart = new Chart(ctx, {
      type: 'line',
      data: {
        labels: points.map(p => p.date),
        datasets: [
          {
            label: 'Portfolio Value',
            data: points.map(p => p.totalValue),
            borderColor: '#4f8ef7',
            backgroundColor: 'rgba(79, 142, 247, 0.08)',
            fill: true,
            tension: 0.25,
            pointRadius: pointRadii,
            pointHoverRadius: pointHoverRadii,
            pointBackgroundColor: pointColors,
            pointBorderColor: pointBorderColors,
            pointBorderWidth: pointBorderWidths,
          }
        ]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        interaction: { mode: 'index', intersect: false },
        scales: {
          x: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Date', font: { weight: 'bold' }, color: '#8da0bf' },
            ticks: {
              color: '#8da0bf',
              maxTicksLimit: 20,
              maxRotation: 45,
            }
          },
          y: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Total Value (€)', font: { weight: 'bold' }, color: '#8da0bf' },
            ticks: {
              color: '#8da0bf',
              callback: (value) => `€${Number(value).toLocaleString('de-IE', { maximumFractionDigits: 0 })}`
            }
          }
        },
        plugins: {
          legend: { display: false },
          tooltip: {
            backgroundColor: '#172040',
            borderColor: '#1f2e4a',
            borderWidth: 1,
            titleColor: '#e4eaf5',
            bodyColor: '#8da0bf',
            callbacks: {
              title: (items) => {
                const idx = items[0].dataIndex;
                const pt = points[idx];
                return pt.hasBuy ? `${pt.date}   Buy recorded` : pt.date;
              },
              label: (tooltipCtx) =>
                ` Portfolio: ${this.formatCurrency(tooltipCtx.parsed.y as number)}`
            }
          }
        }
      }
    });
  }

  loadPortfolioEvolution(): void {
    this.evolutionLoading = true;
    this.evolutionChartRendered = false;
    this.evolutionChart?.destroy();
    this.evolutionChart = null;
    this.apiService.getPortfolioEvolution().subscribe({
      next: (data) => {
        this.portfolioEvolution = data;
        this.evolutionLoading = false;
        this.cdr.markForCheck();
      },
      error: (err) => {
        console.error('Error loading portfolio evolution:', err);
        this.evolutionLoading = false;
        this.cdr.markForCheck();
      }
    });
  }

  setHoldingsTab(tab: 'table' | 'evolution'): void {
    this.activeHoldingsTab = tab;
    if (tab === 'evolution') {
      this.evolutionChartRendered = false;
      this.evolutionChart?.destroy();
      this.evolutionChart = null;
    }
    this.cdr.markForCheck();
  }

  loadDashboard(): void {
    console.log('Loading dashboard...');
    this.loading = true;
    this.error = null;
    this.chartRendered = false;
    this.pieChart?.destroy();
    this.pieChart = null;
    this.apiService.getDashboard().subscribe({
      next: (data: DashboardDto) => {
        console.log('Dashboard data received:', data);
        this.dashboard = data;
        this.loading = false;
        this.cdr.markForCheck();
      },
      error: (err: any) => {
        console.error('Error loading dashboard:', err);
        this.error = 'Failed to load dashboard. Please ensure the API is running.';
        this.loading = false;
        this.cdr.markForCheck();
      }
    });
  }

  formatCurrency(value: number): string {
    return new Intl.NumberFormat('de-IE', {
      style: 'currency',
      currency: 'EUR',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    }).format(value);
  }

  formatPercent(value: number): string {
    return value >= 0 ? `+${value.toFixed(2)}%` : `${value.toFixed(2)}%`;
  }

  formatQuantity(value: number): string {
    return value.toFixed(4);
  }

  getMetricsClass(gainLossEur: number): string {
    return gainLossEur >= 0 ? 'positive' : 'negative';
  }

  onAddTransactionClick(): void {
    this.showAddTransactionModal = true;
  }

  onTransactionAdded(): void {
    this.showAddTransactionModal = false;
    this.loadDashboard();
  }

  onTransactionCancelled(): void {
    this.showAddTransactionModal = false;
  }

  onBuyHistoryClick(holdingId: number): void {
    this.selectedHoldingId = holdingId;
    this.showBuyHistoryModal = true;
  }

  onHistoryModalClosed(): void {
    this.showBuyHistoryModal = false;
    this.selectedHoldingId = null;
  }

  getPriceSourceLabel(source: string | null): string {
    if (!source) return 'N/A';
    const labels: { [key: string]: string } = {
      'Eodhd': 'Eodhd',
      'Yahoo': 'Yahoo',
      'Cache': 'Cached'
    };
    return labels[source] || 'Unknown';
  }

  getPriceSourceDescription(source: string | null): string {
    if (!source) return 'Price data unavailable';
    const descriptions: { [key: string]: string } = {
      'Eodhd': 'Real-time price from Eodhd API (Premium)',
      'Yahoo': 'Real-time price from Yahoo Finance',
      'Cache': 'Cached price from last update'
    };
    return descriptions[source] || 'Unknown source';
  }

}

